  // Global search endpoint
  app.get("/api/search", requireAuth(), async (req, res) => {
    try {
      const query = (req.query.q as string || '').trim();
      
      if (!query || query.length < 2) {
        return res.json({ results: [] });
      }

      const searchPattern = `%${query}%`;
      const userId = getAuthenticatedUserIdOrFail(req, res);
      if (!userId) return;

      // Search across different entities in parallel
      // Only search entities with detail pages (clients, leads, tasks)
      const [clientData, leadData, taskData] = await Promise.all([
        // Search clients
        db.select({
          id: clients.id,
          name: clients.name,
          company: clients.company,
        })
        .from(clients)
        .where(
          or(
            like(clients.name, searchPattern),
            like(clients.company, searchPattern),
            like(clients.email, searchPattern)
          )
        )
        .limit(5),

        // Search leads
        db.select({
          id: leads.id,
          name: leads.name,
          company: leads.company,
        })
        .from(leads)
        .where(
          or(
            like(leads.name, searchPattern),
            like(leads.company, searchPattern),
            like(leads.email, searchPattern)
          )
        )
        .limit(5),

        // Search tasks
        db.select({
          id: tasks.id,
          title: tasks.title,
          description: tasks.description,
        })
        .from(tasks)
        .where(
          or(
            like(tasks.title, searchPattern),
            like(tasks.description, searchPattern)
          )
        )
        .limit(5),
      ]);

      // Format results with type labels
      const results = [
        ...clientData.map(c => ({
          id: c.id,
          name: c.name,
          type: 'client',
          description: c.company || '',
        })),
        ...leadData.map(l => ({
          id: l.id,
          name: l.name,
          type: 'lead',
          description: l.company || '',
        })),
        ...taskData.map(t => ({
          id: t.id,
          name: t.title,
          type: 'task',
          description: t.description,
        })),
      ];

      res.json({ results });
    } catch (error) {
      console.error("Error in global search:", error);
      res.status(500).json({ error: "Search failed" });
    }
  });

  // ===== CRITICAL FIX: TIME TRACKING API ENDPOINT =====
  // COMPLETELY SELF-CONTAINED - NO IMPORTS TO AVOID ALL DRIZZLE CONFLICTS
  // This is a minimal, working endpoint with all logic inline
  app.post("/api/reports/time-tracking", requireAuth(), async (req, res) => {
    try {
    // Helper function to format date in local time (not UTC)
    // This prevents timezone shift issues where toISOString() converts to UTC
    const formatLocalDate = (dateInput: Date | string): string => {
      const d = new Date(dateInput);
      const year = d.getFullYear();
      const month = String(d.getMonth() + 1).padStart(2, '0');
      const day = String(d.getDate()).padStart(2, '0');
      return `${year}-${month}-${day}`;
    };
      console.log("🚀🚀🚀 SELF-CONTAINED TIME TRACKING ENDPOINT CALLED! 🚀🚀🚀");
      console.log("SELF-CONTAINED TIME TRACKING ENDPOINT: Request received:", req.body);
      
      // Use proper authentication that respects impersonation
      const authenticatedUserId = getAuthenticatedUserIdOrFail(req, res);
      if (!authenticatedUserId) return; // getAuthenticatedUserIdOrFail already sent 401 response
      
      // Simple inline validation
      const { dateFrom, dateTo, userId, clientId, taskStatus, reportType, tags, departmentFilter } = req.body;
      
      if (!dateFrom || !dateTo) {
        return res.status(400).json({
          error: "Missing required fields",
          message: "dateFrom and dateTo are required"
        });
      }
      
      // Check if user is admin or has view_all timesheets permission
      const userIsAdmin = await isCurrentUserAdmin(req);
      const canViewAllTimesheets = userIsAdmin || await hasGranularPermission(authenticatedUserId, 'reports.timesheet.view_all');
      
      // Enforce user-level filtering for users without view-all permission
      let effectiveUserId = userId;
      if (!canViewAllTimesheets) {
        // Users without permission can ONLY see their own data
        effectiveUserId = authenticatedUserId;
      } else if (!userId || userId === "all") {
        // User with permission selected "All Users" - show all data
        effectiveUserId = undefined;
      }
      
      // If department filter is set, get staff IDs in that department
      let departmentUserIds: Set<string> | undefined;
      if (departmentFilter && departmentFilter !== "all") {
        const departmentStaff = await db
          .select({ id: staff.id })
          .from(staff)
          .where(eq(staff.department, departmentFilter));
        departmentUserIds = new Set(departmentStaff.map(s => s.id));
        
        // If also filtering by specific user, ensure they're in the department
        if (effectiveUserId && !departmentUserIds.has(effectiveUserId)) {
          // User not in department - return empty result
          return res.json({
            data: { tasks: [], userSummaries: [], clientBreakdowns: [], categoryBreakdowns: [], grandTotal: 0 }
          });
        }
      }

      // Get actual time entries from the database
      console.log("FETCHING REAL TIME ENTRIES FROM DATABASE...");
      const realTimeEntries = await appStorage.getTimeEntriesByDateRange(
        dateFrom, 
        dateTo, 
        effectiveUserId, 
        clientId
      );
      
      console.log("REAL TIME ENTRIES FOUND:", realTimeEntries.length, "tasks");

      // Also fetch event time entries (auto-logged from calendar events marked as "Showed")
      console.log("FETCHING EVENT TIME ENTRIES FROM DATABASE...");
      const eventTimeEntriesResult = await db
        .select()
        .from(eventTimeEntries)
        .where(
          and(
            gte(eventTimeEntries.startTime, new Date(dateFrom)),
            lte(eventTimeEntries.startTime, new Date(dateTo)),
            effectiveUserId ? eq(eventTimeEntries.userId, effectiveUserId) : sql`1=1`,
            clientId ? eq(eventTimeEntries.clientId, clientId) : sql`1=1`
          )
        );
      
      console.log("EVENT TIME ENTRIES FOUND:", eventTimeEntriesResult.length, "entries");

      
      // Transform the real data to match the expected format
      const actualTasks = realTimeEntries;
      
      // Filter tasks based on date range and other filters
      const filteredTasks = actualTasks.filter(task => {
        // Filter by user if specified - use entry-level filtering instead of task-level
        if (effectiveUserId) {
          const hasUserEntries = task.timeEntries?.some(entry => entry.userId === effectiveUserId);
          if (!hasUserEntries) return false;
        }
        
        // Filter by client if specified
        if (clientId === "no-client") {
          // Special filter: show only tasks with no client assigned
          if (task.clientId) return false;
        } else if (clientId && task.clientId !== clientId) {
          return false;
        }
        
        // Filter by task status if specified
        if (taskStatus && taskStatus.length > 0 && !taskStatus.includes(task.status)) return false;
        
        // Filter by tags if specified
        if (tags && Array.isArray(tags) && tags.length > 0) {
          const taskTags = (task.tags as string[]) || [];
          const hasMatchingTag = tags.some((tag: string) => taskTags.includes(tag));
          if (!hasMatchingTag) return false;
        }
        
        // Check if task has time entries in the date range
        if (!task.timeEntries || task.timeEntries.length === 0) return false;
        
        const hasEntriesInRange = task.timeEntries.some(entry => {
          if (!entry.startTime) return false;
          const entryDate = formatLocalDate(entry.startTime);
          return entryDate >= dateFrom && entryDate <= dateTo;
        });
        
        return hasEntriesInRange;
      });
      
      // Process tasks and aggregate data
      const tasksWithDetails = filteredTasks.map(task => {
        const timeEntriesByDate = {};
        
        task.timeEntries.forEach(entry => {
          if (!entry.startTime) return;
          const entryDate = formatLocalDate(entry.startTime);
          if (entryDate >= dateFrom && entryDate <= dateTo) {
            if (!timeEntriesByDate[entryDate]) {
              timeEntriesByDate[entryDate] = [];
            }
            timeEntriesByDate[entryDate].push(entry);
          }
        });
        
        const totalTracked = Object.values(timeEntriesByDate)
          .flat()
          .reduce((sum, entry) => sum + (entry.duration || 0), 0);
        
        return {
          ...task,
          timeEntriesByDate,
          totalTracked
        };
      });
      
      // Create a cache for user lookups to avoid repeated database queries
      const userLookupCache = new Map();
      const userRoleLookupCache = new Map();
      
      // Helper function to get user name and role from database
      const getUserName = async (userId) => {
        if (userLookupCache.has(userId)) {
          return userLookupCache.get(userId);
        }
        
        try {
          const staffWithRole = await db.select({
            firstName: staff.firstName,
            lastName: staff.lastName,
            roleName: roles.name
          })
          .from(staff)
          .leftJoin(roles, eq(staff.roleId, roles.id))
          .where(eq(staff.id, userId))
          .limit(1);
          
          if (staffWithRole.length > 0) {
            const fullName = `${staffWithRole[0].firstName} ${staffWithRole[0].lastName}`;
            userLookupCache.set(userId, fullName);
            userRoleLookupCache.set(userId, staffWithRole[0].roleName || 'User');
            return fullName;
          }
        } catch (error) {
          console.error('Error looking up user:', userId, error);
        }
        
        userLookupCache.set(userId, 'Development User');
        userRoleLookupCache.set(userId, 'User');
        return 'Development User';
      };

      // Calculate user summaries from real data
      const userMap = new Map();
      
      // First pass: collect all unique user IDs and batch lookup their names
      const uniqueUserIds = new Set();
      tasksWithDetails.forEach(task => {
        if (!task.timeEntries) return;
        task.timeEntries.forEach(entry => {
          if (!entry.startTime || !entry.userId) return;
          const entryDate = formatLocalDate(entry.startTime);
          if (entryDate >= dateFrom && entryDate <= dateTo) {
            let resolvedEntryUserId = entry.userId;
            if (IS_DEVELOPMENT && entry.userId === 'current-user') {
              resolvedEntryUserId = authenticatedUserId;
            }
            uniqueUserIds.add(resolvedEntryUserId);
          }
        });
      });

      // Batch lookup all user names at once
      for (const userId of uniqueUserIds) {
        await getUserName(userId);
      }
      
      tasksWithDetails.forEach(task => {
        if (!task.timeEntries) return;
        
        task.timeEntries.forEach(entry => {
          if (!entry.startTime || !entry.userId) return;
          
          const entryDate = formatLocalDate(entry.startTime);
          if (entryDate < dateFrom || entryDate > dateTo) return;
          
          // Handle development mode user ID mapping
          let resolvedEntryUserId = entry.userId;
          if (IS_DEVELOPMENT && entry.userId === 'current-user') {
            resolvedEntryUserId = authenticatedUserId;
          }
          
          // Filter by effectiveUserId if specified
          if (effectiveUserId && resolvedEntryUserId !== effectiveUserId) {
            return; // Skip this entry if it doesn't match the user filter
          }
          
          // Filter by department if specified
          if (departmentUserIds && !departmentUserIds.has(resolvedEntryUserId)) {
            return;
          }
          
          console.log("⏱️ Processing time entry:", { 
            taskId: task.id, 
            userId: resolvedEntryUserId,
            userName: entry.userName,
            duration: entry.duration,
            entryDate 
          });
          
          if (!userMap.has(resolvedEntryUserId)) {
            userMap.set(resolvedEntryUserId, {
              userId: resolvedEntryUserId,
              userName: entry.userName || userLookupCache.get(resolvedEntryUserId) || 'Development User',
              userRole: userRoleLookupCache.get(resolvedEntryUserId) || 'User',
              totalTime: 0,
              tasksWorked: new Set(),
              dailyTotals: {}
            });
          }
          
          const user = userMap.get(resolvedEntryUserId);
          user.totalTime += entry.duration || 0;
          user.tasksWorked.add(task.id);
          user.dailyTotals[entryDate] = (user.dailyTotals[entryDate] || 0) + (entry.duration || 0);
          
          console.log("⏱️ User total time updated:", {
            userId: resolvedEntryUserId,
            totalTime: user.totalTime
          });
        });
      });
      
      // Also add event time entries to user summaries
      console.log("PROCESSING EVENT TIME ENTRIES FOR USER SUMMARIES...");
      for (const eventEntry of eventTimeEntriesResult) {
        // Filter by department if specified
        if (departmentUserIds && !departmentUserIds.has(eventEntry.userId)) {
          continue;
        }
        
        const entryDate = formatLocalDate(eventEntry.startTime);
        
        // Lookup user name
        await getUserName(eventEntry.userId);
        
        if (!userMap.has(eventEntry.userId)) {
          const staffData = await appStorage.getStaffMember(eventEntry.userId);
          userMap.set(eventEntry.userId, {
            userId: eventEntry.userId,
            userName: staffData ? `${staffData.firstName} ${staffData.lastName}` : 'Unknown User',
            userRole: userRoleLookupCache.get(eventEntry.userId) || 'User',
            totalTime: 0,
            tasksWorked: new Set(),
            dailyTotals: {}
          });
        }
        
        const user = userMap.get(eventEntry.userId);
        user.totalTime += eventEntry.duration || 0;
        user.tasksWorked.add(`event-${eventEntry.id}`); // Use event prefix to distinguish from tasks
        user.dailyTotals[entryDate] = (user.dailyTotals[entryDate] || 0) + (eventEntry.duration || 0);
        
        console.log("⏱️ Event time entry added:", {
          eventId: eventEntry.id,
          userId: eventEntry.userId,
          duration: eventEntry.duration,
          entryDate
        });
      }
      console.log("EVENT TIME ENTRIES PROCESSED");

      const userSummaries = Array.from(userMap.values()).map(user => ({
        ...user,
        tasksWorked: user.tasksWorked.size
      }));
      
      // Calculate client breakdowns from real data
      const clientMap = new Map();
      
      tasksWithDetails.forEach(task => {
        if (!task.clientId || !task.timeEntries) return;
        
        if (!clientMap.has(task.clientId)) {
          clientMap.set(task.clientId, {
            clientId: task.clientId,
            clientName: task.clientName || 'Unknown Client',
            totalTime: 0,
            tasksCount: new Set(),
            userMap: new Map()
          });
        }
        
        const client = clientMap.get(task.clientId);
        client.tasksCount.add(task.id);
        
        task.timeEntries.forEach(entry => {
          if (!entry.startTime || !entry.userId) return;
          
          const entryDate = formatLocalDate(entry.startTime);
          if (entryDate < dateFrom || entryDate > dateTo) return;
          
          // Handle development mode user ID mapping
          let resolvedEntryUserId = entry.userId;
          if (IS_DEVELOPMENT && entry.userId === 'current-user') {
            resolvedEntryUserId = authenticatedUserId;
          }
          
          // Filter by effectiveUserId if specified
          if (effectiveUserId && resolvedEntryUserId !== effectiveUserId) {
            return; // Skip this entry if it doesn't match the user filter
          }
          
          // Filter by department if specified
          if (departmentUserIds && !departmentUserIds.has(resolvedEntryUserId)) {
            return;
          }
          
          client.totalTime += entry.duration || 0;
          
          if (!client.userMap.has(resolvedEntryUserId)) {
            client.userMap.set(resolvedEntryUserId, {
              userId: resolvedEntryUserId,
              userName: entry.userName || userLookupCache.get(resolvedEntryUserId) || 'Development User',
              userRole: userRoleLookupCache.get(resolvedEntryUserId) || 'User',
              totalTime: 0,
              tasksWorked: new Set(),
              dailyTotals: {}
            });
          }
          
          const user = client.userMap.get(resolvedEntryUserId);
          user.totalTime += entry.duration || 0;
          user.tasksWorked.add(task.id);
          user.dailyTotals[entryDate] = (user.dailyTotals[entryDate] || 0) + (entry.duration || 0);
        });
      });
      
      const clientBreakdowns = Array.from(clientMap.values()).map(client => ({
        clientId: client.clientId,
        clientName: client.clientName,
        totalTime: client.totalTime,
        tasksCount: client.tasksCount.size,
        users: Array.from(client.userMap.values()).map(user => ({
          ...user,
          tasksWorked: user.tasksWorked.size
        }))
      }));
      
      // Calculate grand total
      const grandTotal = userSummaries.reduce((sum, user) => sum + user.totalTime, 0);

      // Calculate category breakdowns from real data
      const categoryMap = new Map();
      const categoryNameCache = new Map();

      // Fetch all task categories for name lookups
      const allTaskCategories = await db.select({ id: taskCategories.id, name: taskCategories.name, color: taskCategories.color }).from(taskCategories);
      allTaskCategories.forEach(cat => categoryNameCache.set(cat.id, { name: cat.name, color: cat.color }));

      tasksWithDetails.forEach(task => {
        if (!task.timeEntries) return;
        const catId = task.categoryId || 'uncategorized';
        const catInfo = categoryNameCache.get(catId) || { name: 'Uncategorized', color: '#94a3b8' };

        if (!categoryMap.has(catId)) {
          categoryMap.set(catId, {
            categoryId: catId,
            categoryName: catInfo.name,
            categoryColor: catInfo.color,
            totalTime: 0,
            tasksCount: new Set(),
            userMap: new Map()
          });
        }

        const category = categoryMap.get(catId);
        category.tasksCount.add(task.id);

        task.timeEntries.forEach(entry => {
          if (!entry.startTime || !entry.userId) return;
          const entryDate = formatLocalDate(entry.startTime);
          if (entryDate < dateFrom || entryDate > dateTo) return;

          let resolvedEntryUserId = entry.userId;
          if (IS_DEVELOPMENT && entry.userId === 'current-user') {
            resolvedEntryUserId = authenticatedUserId;
          }
          if (effectiveUserId && resolvedEntryUserId !== effectiveUserId) return;
          if (departmentUserIds && !departmentUserIds.has(resolvedEntryUserId)) return;

          category.totalTime += entry.duration || 0;

          if (!category.userMap.has(resolvedEntryUserId)) {
            category.userMap.set(resolvedEntryUserId, {
              userId: resolvedEntryUserId,
              userName: entry.userName || userLookupCache.get(resolvedEntryUserId) || 'Unknown User',
              userRole: userRoleLookupCache.get(resolvedEntryUserId) || 'User',
              totalTime: 0,
              tasksWorked: new Set()
            });
          }

          const user = category.userMap.get(resolvedEntryUserId);
          user.totalTime += entry.duration || 0;
          user.tasksWorked.add(task.id);
        });
      });

      const categoryBreakdowns = Array.from(categoryMap.values())
        .map(cat => ({
          categoryId: cat.categoryId,
          categoryName: cat.categoryName,
          categoryColor: cat.categoryColor,
          totalTime: cat.totalTime,
          tasksCount: cat.tasksCount.size,
          users: Array.from(cat.userMap.values()).map(user => ({
            ...user,
            tasksWorked: user.tasksWorked.size
          }))
        }))
        .sort((a, b) => b.totalTime - a.totalTime);

      const reportData = {
        tasks: tasksWithDetails,
        userSummaries,
        clientBreakdowns,
        categoryBreakdowns,
        grandTotal
      };
      
      console.log("SELF-CONTAINED TIME TRACKING ENDPOINT: Report generated successfully:", {
        tasksCount: reportData.tasks.length,
        userSummariesCount: reportData.userSummaries.length,
        clientBreakdownsCount: reportData.clientBreakdowns.length,
        grandTotal: reportData.grandTotal
      });
      
      // Return response in expected format
      res.status(200).json({
        success: true,
        filters: { dateFrom, dateTo, userId, clientId, taskStatus: taskStatus || [], reportType: reportType || 'detailed' },
        data: reportData,
        meta: {
          dateRange: { from: dateFrom, to: dateTo },
          generatedAt: new Date().toISOString(),
          generatedBy: authenticatedUserId,
          totalTasks: reportData.tasks.length,
          totalUsers: reportData.userSummaries.length,
          totalClients: reportData.clientBreakdowns.length,
          grandTotalHours: Math.round((reportData.grandTotal / 3600) * 100) / 100
        }
      });
      
    } catch (error) {
      console.error("SELF-CONTAINED TIME TRACKING ENDPOINT: Error:", error);
      res.status(500).json({
        error: "Failed to generate time tracking report",
        message: error instanceof Error ? error.message : "Unknown error"
      });
    }
  });

  app.post("/api/reports/cost-per-client", requireAuth(), async (req, res) => {
    try {
      const userId = getAuthenticatedUserIdOrFail(req, res);
      if (!userId) return;

      const isAdminUser = await isCurrentUserAdmin(req);
      let hasAccess = isAdminUser;

      if (!hasAccess) {
        const userRolesList = await db
          .select({ roleId: userRoles.roleId })
          .from(userRoles)
          .where(eq(userRoles.userId, userId));
        const roleIds = userRolesList.map(ur => ur.roleId).filter(Boolean);

        const staffRecord = await db.select({ roleId: staff.roleId }).from(staff).where(eq(staff.id, userId)).limit(1);
        if (staffRecord.length > 0 && staffRecord[0].roleId && !roleIds.includes(staffRecord[0].roleId)) {
          roleIds.push(staffRecord[0].roleId);
        }

        if (roleIds.length > 0) {
          const perms = await db
            .select({ permissionKey: granularPermissions.permissionKey })
            .from(granularPermissions)
            .where(
              and(
                inArray(granularPermissions.roleId, roleIds),
                eq(granularPermissions.permissionKey, 'reports.cost_per_client.view'),
                eq(granularPermissions.enabled, true)
              )
            );
          hasAccess = perms.length > 0;
        }
      }

      if (!hasAccess) {
        return res.status(403).json({ error: "You don't have permission to view cost per client reports" });
      }

      const { dateFrom, dateTo } = req.body;
      if (!dateFrom || !dateTo) {
        return res.status(400).json({ error: "dateFrom and dateTo are required" });
      }

      const formatLocalDate = (dateInput: Date | string): string => {
        const d = new Date(dateInput);
        return d.toLocaleDateString('en-CA', { timeZone: 'America/New_York' });
      };

      const taskTimeEntries = await appStorage.getTimeEntriesByDateRange(dateFrom, dateTo);

      const minutesMap: Record<string, Record<string, number>> = {};
      const userNames: Record<string, string> = {};
      const userDepartments: Record<string, string> = {};
      const clientNames: Record<string, string> = {};

      for (const task of taskTimeEntries) {
        if (!task.timeEntries || task.timeEntries.length === 0) continue;
        const taskClientId = task.clientId || "__no_client__";
        if (task.clientId) {
          clientNames[task.clientId] = (task as any).clientName || task.clientId;
        }

        for (const entry of task.timeEntries) {
          if (!entry.startTime || !entry.userId || !entry.duration) continue;
          const entryDate = formatLocalDate(entry.startTime);
          if (entryDate < dateFrom || entryDate > dateTo) continue;

          const uid = entry.userId;
          if (!minutesMap[uid]) minutesMap[uid] = {};
          minutesMap[uid][taskClientId] = (minutesMap[uid][taskClientId] || 0) + (entry.duration || 0);

          if (!userNames[uid] && entry.userName) {
            userNames[uid] = entry.userName;
          }
        }
      }

      const estFromDate = new Date(dateFrom + "T00:00:00-05:00");
      const estToDate = new Date(dateTo + "T23:59:59-05:00");

      const eventEntries = await db
        .select()
        .from(eventTimeEntries)
        .where(
          and(
            gte(eventTimeEntries.startTime, estFromDate),
            lte(eventTimeEntries.startTime, estToDate)
          )
        );

      for (const entry of eventEntries) {
        if (!entry.duration) continue;
        const entryDate = formatLocalDate(entry.startTime!);
        if (entryDate < dateFrom || entryDate > dateTo) continue;
        const cid = entry.clientId || "__no_client__";
        const uid = entry.userId;
        if (!minutesMap[uid]) minutesMap[uid] = {};
        minutesMap[uid][cid] = (minutesMap[uid][cid] || 0) + entry.duration;
      }

      const allUserIds = Object.keys(minutesMap);
      if (allUserIds.length > 0) {
        const staffRows = await db.select({
          id: staff.id,
          firstName: staff.firstName,
          lastName: staff.lastName,
          annualSalary: staff.annualSalary,
          department: staff.department,
        }).from(staff).where(inArray(staff.id, allUserIds));

        const reportFromDate = new Date(dateFrom + "T00:00:00");
        const reportToDate = new Date(dateTo + "T00:00:00");
        const reportDays = Math.max(1, Math.round((reportToDate.getTime() - reportFromDate.getTime()) / (1000 * 60 * 60 * 24)) + 1);

        for (const s of staffRows) {
          userNames[s.id] = `${s.firstName} ${s.lastName}`;
          if (s.department) userDepartments[s.id] = s.department;
          if (s.annualSalary) {
            const annualSalary = parseFloat(s.annualSalary);
            const hourlyRate = annualSalary / 2080;
            const dailyRate = annualSalary / 365;
            const periodCap = dailyRate * reportDays;

            let totalUncappedCost = 0;
            const clientCosts: Record<string, number> = {};
            for (const clientId of Object.keys(minutesMap[s.id] || {})) {
              const minutes = minutesMap[s.id][clientId];
              const uncappedCost = (minutes / 60) * hourlyRate;
              clientCosts[clientId] = uncappedCost;
              totalUncappedCost += uncappedCost;
            }

            if (totalUncappedCost > periodCap && totalUncappedCost > 0) {
              for (const clientId of Object.keys(clientCosts)) {
                const proportion = clientCosts[clientId] / totalUncappedCost;
                minutesMap[s.id][clientId + "__cost"] = parseFloat((periodCap * proportion).toFixed(2));
              }
            } else {
              for (const clientId of Object.keys(clientCosts)) {
                minutesMap[s.id][clientId + "__cost"] = parseFloat(clientCosts[clientId].toFixed(2));
              }
            }
          }
        }
      }

      const allClientIds = new Set<string>();
      for (const uid of allUserIds) {
        for (const key of Object.keys(minutesMap[uid])) {
          if (!key.endsWith("__cost")) {
            allClientIds.add(key);
          }
        }
      }

      if (allClientIds.size > 0) {
        const realClientIds = [...allClientIds].filter(id => id !== "__no_client__");
        if (realClientIds.length > 0) {
          const clientRows = await db.select({ id: clients.id, company: clients.company, name: clients.name })
            .from(clients)
            .where(inArray(clients.id, realClientIds));
          for (const c of clientRows) {
            clientNames[c.id] = c.company || c.name || c.id;
          }
        }
      }

      const clientColumns = [...allClientIds].sort((a, b) => {
        if (a === "__no_client__") return 1;
        if (b === "__no_client__") return -1;
        return (clientNames[a] || a).localeCompare(clientNames[b] || b);
      });

      const rows = allUserIds.map(uid => {
        const cells: Record<string, { minutes: number; cost: number }> = {};
        let totalMinutes = 0;
        let totalCost = 0;

        for (const cid of clientColumns) {
          const minutes = minutesMap[uid]?.[cid] || 0;
          const cost = minutesMap[uid]?.[cid + "__cost"] || 0;
          cells[cid] = { minutes, cost };
          totalMinutes += minutes;
          totalCost += cost;
        }

        return {
          userId: uid,
          userName: userNames[uid] || "Unknown User",
          department: userDepartments[uid] || "",
          cells,
          totalMinutes,
          totalCost: parseFloat(totalCost.toFixed(2)),
        };
      }).sort((a, b) => a.userName.localeCompare(b.userName));

      const columnTotals: Record<string, { minutes: number; cost: number }> = {};
      let grandTotalMinutes = 0;
      let grandTotalCost = 0;

      for (const cid of clientColumns) {
        let colMinutes = 0;
        let colCost = 0;
        for (const row of rows) {
          colMinutes += row.cells[cid]?.minutes || 0;
          colCost += row.cells[cid]?.cost || 0;
        }
        columnTotals[cid] = { minutes: colMinutes, cost: parseFloat(colCost.toFixed(2)) };
        grandTotalMinutes += colMinutes;
        grandTotalCost += colCost;
      }

      res.json({
        columns: clientColumns.map(cid => ({
          clientId: cid,
          clientName: cid === "__no_client__" ? "No Client" : (clientNames[cid] || cid),
        })),
        rows,
        columnTotals,
        grandTotalMinutes,
        grandTotalCost: parseFloat(grandTotalCost.toFixed(2)),
      });
    } catch (error) {
      console.error("Cost per client report error:", error);
      res.status(500).json({ error: "Failed to generate cost per client report" });
    }
  });

