  // Task Stage Analytics Report API endpoint
  app.post("/api/reports/stage-analytics", requireAuth(), requirePermission('reporting', 'canView'), async (req, res) => {
    try {
      console.log("📊 STAGE ANALYTICS REPORT ENDPOINT CALLED");
      
      const { dateFrom, dateTo, clientId, userId } = req.body;
      
      // Fetch all tasks with status history
      let allTasks = await appStorage.getTasks();
      
      // Apply filters
      if (clientId && clientId !== 'all' && clientId !== 'no-client') {
        allTasks = allTasks.filter(t => t.clientId === clientId);
      } else if (clientId === 'no-client') {
        allTasks = allTasks.filter(t => !t.clientId);
      }
      
      if (userId && userId !== 'all') {
        allTasks = allTasks.filter(t => t.assignedTo === userId);
      }
      
      // Filter by date range if provided
      if (dateFrom && dateTo) {
        const fromDate = new Date(dateFrom);
        const toDate = new Date(dateTo);
        toDate.setHours(23, 59, 59, 999);
        
        allTasks = allTasks.filter(t => {
          const createdAt = t.createdAt ? new Date(t.createdAt) : null;
          return createdAt && createdAt >= fromDate && createdAt <= toDate;
        });
      }
      
      // Define all possible stages
      const stages = ['todo', 'in_progress', 'completed', 'cancelled', 'on_hold', 'blocked', 'review'];
      
      // Calculate stage analytics
      const stageStats: Record<string, {
        stage: string;
        avgTimeInStage: number; // milliseconds
        totalTimeInStage: number; // milliseconds
        totalTimeTracked: number; // minutes from time entries
        hitCount: number; // total times any task entered this stage
        taskCount: number; // number of tasks that have been in this stage
        backAndForthCount: number; // tasks that hit this stage more than once
      }> = {};
      
      // Initialize stats for all stages
      stages.forEach(stage => {
        stageStats[stage] = {
          stage,
          avgTimeInStage: 0,
          totalTimeInStage: 0,
          totalTimeTracked: 0,
          hitCount: 0,
          taskCount: 0,
          backAndForthCount: 0
        };
      });
      
      // Process each task
      for (const task of allTasks) {
        const statusHistory = (task.statusHistory as any[]) || [];
        const timeEntries = (task.timeEntries as any[]) || [];
        
        // Track which stages this task has been in and how many times
        const stageHitCounts: Record<string, number> = {};
        
        for (const entry of statusHistory) {
          const stage = entry.status;
          if (!stageStats[stage]) {
            stageStats[stage] = {
              stage,
              avgTimeInStage: 0,
              totalTimeInStage: 0,
              totalTimeTracked: 0,
              hitCount: 0,
              taskCount: 0,
              backAndForthCount: 0
            };
          }
          
          // Count hits
          stageStats[stage].hitCount++;
          stageHitCounts[stage] = (stageHitCounts[stage] || 0) + 1;
          
          // Add duration if available
          if (entry.durationMs) {
            stageStats[stage].totalTimeInStage += entry.durationMs;
          } else if (entry.enteredAt && !entry.exitedAt) {
            // Task is still in this stage - calculate live duration
            const now = new Date().getTime();
            const entered = new Date(entry.enteredAt).getTime();
            stageStats[stage].totalTimeInStage += (now - entered);
          }
          
          // Add time tracked in stage
          if (entry.timeTrackedInStage) {
            stageStats[stage].totalTimeTracked += entry.timeTrackedInStage;
          }
        }
        
        // Count unique tasks per stage and back-and-forth
        for (const [stage, count] of Object.entries(stageHitCounts)) {
          stageStats[stage].taskCount++;
          if (count > 1) {
            stageStats[stage].backAndForthCount++;
          }
        }
        
        // Also calculate time tracked per stage from time entries
        // (This associates time entries with the current stage at the time)
        for (const timeEntry of timeEntries) {
          if (!timeEntry.startTime) continue;
          
          const entryTime = new Date(timeEntry.startTime).getTime();
          const duration = timeEntry.duration || 0; // in minutes
          
          // Find which stage the task was in when this time was logged
          let stageAtTime = task.status; // default to current status
          for (const historyEntry of statusHistory) {
            const enteredAt = new Date(historyEntry.enteredAt).getTime();
            const exitedAt = historyEntry.exitedAt ? new Date(historyEntry.exitedAt).getTime() : null;
            
            if (entryTime >= enteredAt && (!exitedAt || entryTime <= exitedAt)) {
              stageAtTime = historyEntry.status;
              break;
            }
          }
          
          if (stageStats[stageAtTime]) {
            stageStats[stageAtTime].totalTimeTracked += duration;
          }
        }
      }
      
      // Calculate averages
      for (const stage in stageStats) {
        const stats = stageStats[stage];
        if (stats.hitCount > 0) {
          stats.avgTimeInStage = stats.totalTimeInStage / stats.hitCount;
        }
      }
      
      // Convert to array and sort by hit count
      const stageAnalytics = Object.values(stageStats)
        .filter(s => s.hitCount > 0)
        .sort((a, b) => b.hitCount - a.hitCount);
      
      // Also get per-task stage breakdown for detailed view
      const taskBreakdowns = allTasks.slice(0, 50).map(task => {
        const statusHistory = (task.statusHistory as any[]) || [];
        return {
          taskId: task.id,
          taskTitle: task.title,
          currentStatus: task.status,
          stageHistory: statusHistory.map(h => ({
            stage: h.status,
            enteredAt: h.enteredAt,
            exitedAt: h.exitedAt,
            durationMs: h.durationMs,
            hitCount: h.hitCount || 1
          }))
        };
      });
      
      res.json({
        stageAnalytics,
        taskBreakdowns,
        totalTasks: allTasks.length,
        tasksWithHistory: allTasks.filter(t => ((t.statusHistory as any[]) || []).length > 0).length
      });
      
    } catch (error: any) {
      console.error("Error fetching stage analytics:", error);
      res.status(500).json({ error: "Failed to fetch stage analytics" });
    }
  });


  // Team Workload Report API endpoint
  // Team Workload Report API endpoint
  app.get("/api/reports/team-workload", requireAuth(), requirePermission('reporting', 'canView'), async (req, res) => {
    try {
      console.log("🧑‍💼 TEAM WORKLOAD REPORT ENDPOINT CALLED");
      
      // Get all team assignments with related staff and client data
      const teamAssignments = await appStorage.getTeamAssignments();
      
      // Get all staff members for reference (ACTIVE ONLY)
      const allStaff = await appStorage.getStaff();
      const activeStaff = allStaff.filter(staff => staff.isActive);
      
      // Get all clients for reference
      const clients = await appStorage.getClients();
      
      // Create workload map - count clients per staff member
      const staffWorkloadMap = new Map<string, {
        staffId: string;
        staffName: string;
        staffRole: string;
        department: string;
        clientCount: number;
        clients: Array<{
          clientId: string;
          clientName: string;
          positions: Array<{
            positionId: string;
            positionLabel: string;
            assignedAt: Date;
          }>;
        }>;
      }>();
      
      // Initialize all ACTIVE staff members with zero assignments
      activeStaff.forEach(staff => {
        staffWorkloadMap.set(staff.id, {
          staffId: staff.id,
          staffName: `${staff.firstName} ${staff.lastName}`,
          staffRole: staff.position || 'Unknown',
          department: staff.department || 'Unknown',
          clientCount: 0,
          clients: []
        });
      });
      
      // Process team assignments to count workload (ACTIVE STAFF ONLY)
      teamAssignments.forEach(assignment => {
        const staffId = assignment.staffId;
        const clientId = assignment.clientId;
        const client = clients.find(c => c.id === clientId);
        
        // Skip assignments for inactive staff members
        if (!staffWorkloadMap.has(staffId)) {
          return; // Skip this assignment - staff member is inactive or doesn't exist
        }
        
        const staffWorkload = staffWorkloadMap.get(staffId)!
        
        // Check if this client is already tracked for this staff member
        let existingClient = staffWorkload.clients.find(c => c.clientId === clientId);
        
        if (!existingClient) {
          // New client for this staff member
          existingClient = {
            clientId,
            clientName: client?.company || client?.name || 'Unknown Client',
            positions: []
          };
          staffWorkload.clients.push(existingClient);
          staffWorkload.clientCount++;
        }
        
        // Add position to this client assignment
        existingClient.positions.push({
          positionId: assignment.position?.id || 'unknown',
          positionLabel: assignment.position?.label || 'Unknown Position',
          assignedAt: assignment.assignedAt || new Date()
        });
      });
      
      // Convert map to array and sort by client count (descending)
      const staffWorkloadData = Array.from(staffWorkloadMap.values())
        .sort((a, b) => b.clientCount - a.clientCount);
      
      // Calculate summary statistics (ACTIVE STAFF ONLY)
      const summary = {
        totalStaff: activeStaff.length,
        staffWithAssignments: staffWorkloadData.filter(s => s.clientCount > 0).length,
        staffWithoutAssignments: staffWorkloadData.filter(s => s.clientCount === 0).length,
        totalAssignments: teamAssignments.length,
        uniqueClientsWithAssignments: new Set(teamAssignments.map(a => a.clientId)).size,
        averageClientsPerStaff: staffWorkloadData.length > 0 ? 
          (staffWorkloadData.reduce((sum, s) => sum + s.clientCount, 0) / staffWorkloadData.length) : 0,
        maxClientsPerStaff: Math.max(...staffWorkloadData.map(s => s.clientCount), 0),
        workloadDistribution: {
          '0_clients': staffWorkloadData.filter(s => s.clientCount === 0).length,
          '1_client': staffWorkloadData.filter(s => s.clientCount === 1).length,
          '2-3_clients': staffWorkloadData.filter(s => s.clientCount >= 2 && s.clientCount <= 3).length,
          '4-5_clients': staffWorkloadData.filter(s => s.clientCount >= 4 && s.clientCount <= 5).length,
          '6_plus_clients': staffWorkloadData.filter(s => s.clientCount >= 6).length,
        }
      };
      
      console.log("TEAM WORKLOAD REPORT: Generated successfully:", {
        totalStaff: summary.totalStaff,
        staffWithAssignments: summary.staffWithAssignments,
        totalAssignments: summary.totalAssignments
      });
      
      res.status(200).json({
        success: true,
        data: {
          staffWorkload: staffWorkloadData,
          summary
        },
        meta: {
          generatedAt: new Date().toISOString(),
          reportType: 'team-workload'
        }
      });
      
    } catch (error) {
      console.error("TEAM WORKLOAD REPORT: Error:", error);
      res.status(500).json({
        error: "Failed to generate team workload report",
        message: error instanceof Error ? error.message : "Unknown error"
      });
    }
  });

  // Client routes - SECURED
  app.get("/api/clients", requireAuth(), requirePermission('clients', 'canView'), async (req, res) => {
    try {
      const page = parseInt(req.query.page as string) || 1;
      const limit = parseInt(req.query.limit as string) || 20;
      const offset = (page - 1) * limit;
      const sortBy = req.query.sortBy as string || "createdAt"; // default sort by creation date
      const sortOrder = req.query.sortOrder as string || "desc"; // default descending (newest first)
      
      // Add cache-busting headers for fresh data
      res.set({
        'Cache-Control': 'no-cache, no-store, must-revalidate',
        'Pragma': 'no-cache',
        'Expires': '0'
      });
      
      const result = await appStorage.getClientsWithPagination(limit, offset, sortBy, sortOrder);
      
      res.json({
        clients: result.clients,
        pagination: {
          page,
          limit,
          total: result.total,
          totalPages: Math.ceil(result.total / limit),
          hasNext: page * limit < result.total,
          hasPrevious: page > 1
        }
      });
    } catch (error) {
      console.error("Error fetching clients:", error);
      console.error("Error details:", JSON.stringify(error, null, 2));
      console.error("Error stack:", error instanceof Error ? error.stack : 'No stack trace');
      
      // Enhanced error handling for common database/Drizzle issues
      if (error instanceof Error) {
        if (error.message.includes('Cannot convert undefined or null to object')) {
          console.error('DRIZZLE ORM ERROR: Query builder received invalid parameters');
          return res.status(500).json({ 
            message: "Database query error - invalid parameters", 
            error: "Query builder failed",
            details: error.message 
          });
        }
        if (error.message.includes('relation') && error.message.includes('does not exist')) {
          console.error('DATABASE ERROR: Table/relation does not exist');
          return res.status(500).json({ 
            message: "Database schema error", 
            error: "Required table not found",
            details: error.message 
          });
        }
        if (error.message.includes('connection')) {
          console.error('DATABASE ERROR: Connection issue');
          return res.status(500).json({ 
            message: "Database connection error", 
            error: "Unable to connect to database",
            details: error.message 
          });
        }
      }
      
      res.status(500).json({ 
        message: "Failed to fetch clients", 
        error: error instanceof Error ? error.message : String(error),
        type: error instanceof Error ? error.constructor.name : typeof error
      });
    }
  });

  app.get("/api/clients/:id", requireAuth(), requirePermission('clients', 'canView'), async (req, res) => {
    try {
      const client = await appStorage.getClient(req.params.id);
      if (!client) {
        return res.status(404).json({ message: "Client not found" });
      }
      res.json(client);
    } catch (error) {
      res.status(500).json({ message: "Failed to fetch client" });
    }
  });


  app.post("/api/clients", requireAuth(), requirePermission('clients', 'canCreate'), async (req, res) => {
    try {
      const userId = getAuthenticatedUserIdOrFail(req, res);
      if (!userId) return; // getAuthenticatedUserIdOrFail already sent 401 response
      
      const validatedData = insertClientSchema.parse(req.body);
      const client = await appStorage.createClient(validatedData);
      
      // If this client was converted from a lead, create a deal from the accepted quote
      if (req.body.leadId) {
        try {
          // Check if a deal already exists for this lead (idempotency check)
          const existingDeal = await db
            .select()
            .from(deals)
            .where(eq(deals.leadId, req.body.leadId))
            .limit(1);

          if (existingDeal && existingDeal.length > 0) {
            console.log(`ℹ️ Deal already exists for lead ${req.body.leadId}, skipping creation`);
          } else {
            // Find the lead
            const lead = await db
              .select()
              .from(leads)
              .where(eq(leads.id, req.body.leadId))
              .limit(1);

            if (lead && lead.length > 0) {
              // Use selectedQuoteId if provided, otherwise find the most recent accepted quote
              let quote = null;
              if (req.body.selectedQuoteId) {
                const selectedQuote = await db
                  .select()
                  .from(quotes)
                  .where(eq(quotes.id, req.body.selectedQuoteId))
                  .limit(1);
                quote = selectedQuote.length > 0 ? selectedQuote[0] : null;
              } else {
                // Find any accepted quotes for this lead
                const acceptedQuotes = await db
                  .select()
                  .from(quotes)
                  .where(and(
                    sql`${quotes.leadId} = ${req.body.leadId}`,
                    eq(quotes.status, 'accepted')
                  ))
                  .orderBy(desc(quotes.createdAt))
                  .limit(1);
                quote = acceptedQuotes.length > 0 ? acceptedQuotes[0] : null;
              }

              if (quote) {
                // Create a deal from the accepted quote
                const dealValue = quote.total || lead[0].value || 0;
                const dealData = {
                  leadId: req.body.leadId,
                  clientId: client.id,
                  name: `${client.name || lead[0].name} - ${lead[0].company || 'Deal'}`,
                  assignedTo: lead[0].assignedTo,
                  value: dealValue,
                  mrr: quote.mrr || 0, // Monthly recurring revenue if available
                  wonDate: new Date(),
                  notes: `Deal created from accepted quote #${quote.id}. Total value: $${dealValue}`,
                };

                await db.insert(deals).values(dealData);
                console.log(`✅ Created deal for client ${client.id} from quote ${quote.id}`);

                // Transfer quote items (products/bundles) to the client
                const items = await db
                  .select()
                  .from(quoteItems)
                  .where(eq(quoteItems.quoteId, quote.id));

                let transferredCount = 0;

                // Transfer each item to the client
                for (const item of items) {
                  if (item.itemType === 'product' && item.productId) {
                    // Check if product already assigned to client
                    const existing = await db
                      .select()
                      .from(clientProducts)
                      .where(
                        and(
                          eq(clientProducts.clientId, client.id),
                          eq(clientProducts.productId, item.productId)
                        )
                      )
                      .limit(1);

                    if (existing.length === 0) {
                      // Add product to client
                      await db.insert(clientProducts).values({
                        clientId: client.id,
                        productId: item.productId,
                      });
                      transferredCount++;
                      console.log(`✅ Transferred product ${item.productId} to client ${client.id}`);
                    }
                  } else if (item.itemType === 'bundle' && item.bundleId) {
                    // Check if bundle already assigned to client
                    const existing = await db
                      .select()
                      .from(clientBundles)
                      .where(
                        and(
                          eq(clientBundles.clientId, client.id),
                          eq(clientBundles.bundleId, item.bundleId)
                        )
                      )
                      .limit(1);

                    if (existing.length === 0) {
                      // Add bundle to client
                      await db.insert(clientBundles).values({
                        clientId: client.id,
                        bundleId: item.bundleId,
                        customQuantities: item.customQuantities,
                      });
                      transferredCount++;
                      console.log(`✅ Transferred bundle ${item.bundleId} to client ${client.id}`);
                    }
                  } else if (item.itemType === 'package' && item.packageId) {
                    // Transfer package to client
                    const existingPkg = await db
                      .select()
                      .from(clientPackages)
                      .where(
                        and(
                          eq(clientPackages.clientId, client.id),
                          eq(clientPackages.packageId, item.packageId)
                        )
                      )
                      .limit(1);

                    if (existingPkg.length === 0) {
                      await db.insert(clientPackages).values({
                        clientId: client.id,
                        packageId: item.packageId,
                        price: item.unitCost?.toString() || '0',
                        status: 'active',
                        customQuantities: item.customQuantities,
                      });
                      transferredCount++;
                      console.log(`✅ Transferred package ${item.packageId} to client ${client.id}`);
                    }

                    // Also transfer individual bundles from within the package
                    const pkgItems = await db
                      .select()
                      .from(packageItems)
                      .where(eq(packageItems.packageId, item.packageId));

                    for (const pkgItem of pkgItems) {
                      if (pkgItem.itemType === 'bundle' && pkgItem.bundleId) {
                        const existingBundle = await db
                          .select()
                          .from(clientBundles)
                          .where(
                            and(
                              eq(clientBundles.clientId, client.id),
                              eq(clientBundles.bundleId, pkgItem.bundleId)
                            )
                          )
                          .limit(1);

                        if (existingBundle.length === 0) {
                          await db.insert(clientBundles).values({
                            clientId: client.id,
                            bundleId: pkgItem.bundleId,
                            customQuantities: item.customQuantities || null,
                          });
                          transferredCount++;
                          console.log(`✅ Transferred bundle ${pkgItem.bundleId} from package ${item.packageId} to client ${client.id}`);
                        }
                      } else if (pkgItem.itemType === 'product' && pkgItem.productId) {
                        const existingProd = await db
                          .select()
                          .from(clientProducts)
                          .where(
                            and(
                              eq(clientProducts.clientId, client.id),
                              eq(clientProducts.productId, pkgItem.productId)
                            )
                          )
                          .limit(1);

                        if (existingProd.length === 0) {
                          await db.insert(clientProducts).values({
                            clientId: client.id,
                            productId: pkgItem.productId,
                          });
                          transferredCount++;
                          console.log(`✅ Transferred product ${pkgItem.productId} from package ${item.packageId} to client ${client.id}`);
                        }
                      }
                    }
                  }
                }

                console.log(`✅ Transferred ${transferredCount} items from quote ${quote.id} to client ${client.id}`);

                // Update lead status to "Won" and move to "Closed Won" pipeline stage
                const closedWonStage = await db
                  .select()
                  .from(leadPipelineStages)
                  .where(sql`LOWER(${leadPipelineStages.name}) = 'closed won'`)
                  .limit(1);

                const updateData: any = {
                  status: 'Won',
                };

                if (closedWonStage.length > 0) {
                  updateData.stageId = closedWonStage[0].id;
                  console.log(`✅ Moving lead ${req.body.leadId} to "Closed Won" stage`);
                }

                await db
                  .update(leads)
                  .set(updateData)
                  .where(eq(leads.id, req.body.leadId));

                console.log(`✅ Updated lead ${req.body.leadId} status to "Won"`);
              } else {
                console.warn(`⚠️ No accepted quote found for lead ${req.body.leadId} - deal not created`);
              }
            }
          }
        } catch (dealError) {
          // Log the error but don't fail the client creation
          console.error('Error creating deal from quote:', dealError);
        }
      }

      let taskGenerationSummary: any = null;

      try {
        const [autoGenSetting] = await db.select().from(taskSettings)
          .where(eq(taskSettings.settingKey, 'task_mapping_auto_generate_on_conversion'));
        const autoGenerateEnabled = (autoGenSetting?.settingValue as any)?.value ?? true;

        if (!autoGenerateEnabled) {
          console.log(`[TaskGen] Auto-generate on conversion is disabled — skipping for client ${client.id}`);
        } else {
          const assignedProducts = await db
            .select({ productId: clientProducts.productId })
            .from(clientProducts)
            .where(eq(clientProducts.clientId, client.id));

        const assignedBundles = await db
          .select({ bundleId: clientBundles.bundleId })
          .from(clientBundles)
          .where(eq(clientBundles.clientId, client.id));

        const assignedPackages = await db
          .select({ packageId: clientPackages.packageId })
          .from(clientPackages)
          .where(eq(clientPackages.clientId, client.id));

        const generationItems: Array<{ productId?: string; bundleId?: string; packageId?: string; quantity: number }> = [];

        for (const cp of assignedProducts) {
          let qty = 1;
          if (req.body.selectedQuoteId) {
            const [qi] = await db.select({ quantity: quoteItems.quantity }).from(quoteItems)
              .where(and(eq(quoteItems.quoteId, req.body.selectedQuoteId), eq(quoteItems.productId, cp.productId), eq(quoteItems.itemType, 'product')))
              .limit(1);
            if (qi) qty = qi.quantity;
          }
          generationItems.push({ productId: cp.productId, quantity: qty });
        }

        for (const cb of assignedBundles) {
          let qty = 1;
          if (req.body.selectedQuoteId) {
            const [qi] = await db.select({ quantity: quoteItems.quantity }).from(quoteItems)
              .where(and(eq(quoteItems.quoteId, req.body.selectedQuoteId), eq(quoteItems.bundleId, cb.bundleId), eq(quoteItems.itemType, 'bundle')))
              .limit(1);
            if (qi) qty = qi.quantity;
          }
          generationItems.push({ bundleId: cb.bundleId, quantity: qty });
        }

        for (const cpkg of assignedPackages) {
          let qty = 1;
          if (req.body.selectedQuoteId) {
            const [qi] = await db.select({ quantity: quoteItems.quantity }).from(quoteItems)
              .where(and(eq(quoteItems.quoteId, req.body.selectedQuoteId), eq(quoteItems.packageId, cpkg.packageId), eq(quoteItems.itemType, 'package')))
              .limit(1);
            if (qi) qty = qi.quantity;
          }
          generationItems.push({ packageId: cpkg.packageId, quantity: qty });
        }

        if (generationItems.length > 0) {
          taskGenerationSummary = await generateTasksFromTemplates({
            clientId: client.id,
            items: generationItems,
            generationType: 'onboarding',
            cycleStartDate: new Date(),
          });

          console.log(`✅ Task generation for client ${client.id}: ${taskGenerationSummary.totalTasksCreated} onboarding tasks created`);
          if (taskGenerationSummary.errors.length > 0) {
            console.warn(`⚠️ Task generation warnings:`, taskGenerationSummary.errors);
          }
        }
        }

        const [cycleLengthSetting] = await db.select().from(taskSettings)
          .where(eq(taskSettings.settingKey, 'task_mapping_default_cycle_length'));
        const defaultCycleLength = (cycleLengthSetting?.settingValue as any)?.value ?? 30;

        const [advanceGenSetting] = await db.select().from(taskSettings)
          .where(eq(taskSettings.settingKey, 'task_mapping_default_advance_generation_days'));
        const defaultAdvanceDays = (advanceGenSetting?.settingValue as any)?.value ?? 3;

        const existingConfig = await db.select().from(clientRecurringConfig)
          .where(eq(clientRecurringConfig.clientId, client.id)).limit(1);

        if (existingConfig.length === 0) {
          await db.insert(clientRecurringConfig).values({
            clientId: client.id,
            cycleStartDate: new Date(),
            cycleLengthDays: defaultCycleLength,
            advanceGenerationDays: defaultAdvanceDays,
            status: 'active',
          });
          console.log(`✅ Created recurring config for client ${client.id} (cycle: ${defaultCycleLength}d, advance: ${defaultAdvanceDays}d)`);
        }
      } catch (taskGenError) {
        console.error('Error generating onboarding tasks (non-blocking):', taskGenError);
      }

      try {
        const briefSections = await appStorage.listBriefSections();
        const clientBrief = await appStorage.getClientBrief(client.id);
        for (const section of briefSections) {
          if (section.defaultTemplate && section.isEnabled) {
            const existing = clientBrief.find(b => b.id === section.id);
            if (!existing?.value || existing.value.trim() === '') {
              await appStorage.setClientBriefValue(client.id, section.id, section.defaultTemplate);
            }
          }
        }
      } catch (templateError) {
        console.error('Error applying default brief templates (non-blocking):', templateError);
      }

      // Log the creation with authenticated user
      await createAuditLog(
        "created",
        "contact",
        client.id,
        client.name || client.email,
        userId, // SECURE: Use authenticated user ID only
        `New contact record created with email: ${client.email}`,
        null,
        { name: client.name, email: client.email, company: client.company },
        req
      );
      
      res.status(201).json({
        ...client,
        taskGenerationSummary: taskGenerationSummary || undefined,
      });
    } catch (error) {
      if (error instanceof z.ZodError) {
        return res.status(400).json({ message: "Invalid data", errors: error.errors });
      }
      
      // Handle duplicate email constraint
      if (error instanceof Error && error.message.includes('duplicate key value violates unique constraint "clients_email_unique"')) {
        return res.status(409).json({ 
          message: "A client with this email already exists", 
          error: "Email must be unique" 
        });
      }
      
      console.error("Error creating client:", error);
      const errorMessage = error instanceof Error ? error.message : "Unknown error";
      res.status(500).json({ message: "Failed to create client", error: errorMessage });
    }
  });

  app.post("/api/leads/:id/convert", requireAuth(), requirePermission('leads', 'canEdit'), async (req, res) => {
    try {
      const leadId = req.params.id;
      const force = req.body?.force === true;

      if (force) {
        console.log(`[LeadConversion] Force mode: resetting conversion state for lead ${leadId}`);
        await db
          .update(leads)
          .set({
            isConverted: false,
            convertedAt: null,
            clientId: null,
            convertedBy: null,
          })
          .where(eq(leads.id, leadId));
      }

      const result = await convertLeadToClient(leadId, "manual");
      console.log(`[LeadConversion] Route handler result:`, JSON.stringify(result));
      res.json(result);
    } catch (error) {
      console.error("Error converting lead to client:", error);
      const errorMessage = error instanceof Error ? error.message : "Unknown error";
      const errorStack = error instanceof Error ? error.stack : undefined;
      console.error("Error stack:", errorStack);
      res.status(500).json({ message: "Failed to convert lead to client", error: errorMessage });
    }
  });

  app.put("/api/clients/:id", requireAuth(), requirePermission('clients', 'canEdit'), async (req, res) => {
    try {
      
      // Get the old client data first for audit logging
      const oldClient = await appStorage.getClient(req.params.id);
      if (!oldClient) {
        console.log("❌ Client not found");
        return res.status(404).json({ message: "Client not found" });
      }
      
      const validatedData = insertClientSchema.partial().parse(req.body);
      
      // Remove undefined values and check if there are valid fields to update
      const filteredData = Object.fromEntries(
        Object.entries(validatedData).filter(([key, value]) => value !== undefined)
      );
      
      if (Object.keys(filteredData).length === 0) {
        console.log("❌ No valid fields to update");
        return res.status(400).json({ message: "No valid client fields to update" });
      }
      
      // Security check for DND changes - Only Admin users can UNCHECK (disable) DND settings
      const currentUserId = getAuthenticatedUserIdOrFail(req, res);
      if (!currentUserId) return; // getAuthenticatedUserIdOrFail already sent 401 response
      
      const dndFieldsBeingDisabled = [];
      if (validatedData.dndAll === false && oldClient.dndAll === true) {
        dndFieldsBeingDisabled.push('dndAll');
      }
      if (validatedData.dndEmail === false && oldClient.dndEmail === true) {
        dndFieldsBeingDisabled.push('dndEmail');
      }
      if (validatedData.dndSms === false && oldClient.dndSms === true) {
        dndFieldsBeingDisabled.push('dndSms');
      }
      if (validatedData.dndCalls === false && oldClient.dndCalls === true) {
        dndFieldsBeingDisabled.push('dndCalls');
      }
      
      if (dndFieldsBeingDisabled.length > 0) {
        
        try {
          // Strict Admin role check - only users with Admin role can disable DND
          const isAdmin = await isCurrentUserAdmin(req);
          
          if (!isAdmin) {
            console.log("❌ Non-Admin user attempted to disable DND settings");
            return res.status(403).json({ 
              message: "Only Admin users can disable DND settings. You can enable DND settings but cannot disable them.",
              restrictedFields: dndFieldsBeingDisabled,
              error: "Admin role required for DND disable operation"
            });
          }
          
          } catch (error) {
          console.error("❌ Error checking Admin role for DND operation:", error);
          return res.status(403).json({ 
            message: "Unable to verify Admin permissions for DND disable operation",
            error: "Permission check failed"
          });
        }
      }
      
      const client = await appStorage.updateClient(req.params.id, filteredData);
      
      if (!client) {
        return res.status(404).json({ message: "Client not found" });
      }
      
      // Sync core fields from customFieldValues back to clients table columns
      if (validatedData.customFieldValues) {
        try {
          const allCustomFields = await db.select().from(customFields);
          const cfv = validatedData.customFieldValues as Record<string, any>;
          const syncUpdates: Record<string, any> = {};
          
          for (const field of allCustomFields) {
            const fieldNameLower = field.name.toLowerCase();
            if (cfv[field.id] !== undefined) {
              if (fieldNameLower === 'email' || fieldNameLower === 'e-mail') {
                syncUpdates.email = cfv[field.id];
              } else if (fieldNameLower === 'phone' || fieldNameLower === 'mobile') {
                syncUpdates.phone = cfv[field.id];
              } else if (fieldNameLower === 'business name' || fieldNameLower === 'company name' || fieldNameLower === 'company') {
                syncUpdates.company = cfv[field.id];
              } else if (fieldNameLower === 'first name' || fieldNameLower === 'firstname') {
                const lastNameField = allCustomFields.find(f => {
                  const n = f.name.toLowerCase();
                  return n === 'last name' || n === 'lastname';
                });
                const lastName = lastNameField ? (cfv[lastNameField.id] || (client.customFieldValues as Record<string, any>)?.[lastNameField.id] || '') : '';
                syncUpdates.name = `${cfv[field.id]} ${lastName}`.trim();
              } else if (fieldNameLower === 'last name' || fieldNameLower === 'lastname') {
                const firstNameField = allCustomFields.find(f => {
                  const n = f.name.toLowerCase();
                  return n === 'first name' || n === 'firstname';
                });
                const firstName = firstNameField ? (cfv[firstNameField.id] || (client.customFieldValues as Record<string, any>)?.[firstNameField.id] || '') : '';
                syncUpdates.name = `${firstName} ${cfv[field.id]}`.trim();
              }
            }
          }
          
          if (Object.keys(syncUpdates).length > 0) {
            const syncedClient = await appStorage.updateClient(req.params.id, syncUpdates);
            if (syncedClient) {
              Object.assign(client, syncedClient);
            }
          }
        } catch (syncErr) {
          console.error('[Client Sync] Error syncing custom field values to core fields:', syncErr);
        }
      }
      
      // Send notification if assignee changed
      if (validatedData.assignee && validatedData.assignee !== oldClient.assignee) {
        void notificationService.notifyClientAssigned(
          validatedData.assignee,
          client.name || client.email,
          currentUserId,
          client.id
        ).catch(err => console.error('[Notification] Failed to send client assignment notification:', err));
      }
      
      // Determine what changed for audit logging
      const changes = [];
      if (validatedData.name && validatedData.name !== oldClient.name) {
        changes.push(`name from "${oldClient.name}" to "${validatedData.name}"`);
      }
      if (validatedData.email && validatedData.email !== oldClient.email) {
        changes.push(`email from "${oldClient.email}" to "${validatedData.email}"`);
      }
      if (validatedData.phone && validatedData.phone !== oldClient.phone) {
        changes.push(`phone from "${oldClient.phone}" to "${validatedData.phone}"`);
      }

      // Check for DND (Do Not Disturb) changes - CRITICAL for compliance
      const dndChanges = [];
      const dndDetails = [];
      
      if (validatedData.dndAll !== undefined && validatedData.dndAll !== oldClient.dndAll) {
        const status = validatedData.dndAll ? "ENABLED" : "DISABLED";
        const action = validatedData.dndAll ? "BLOCKED all communications" : "UNBLOCKED all communications";
        dndChanges.push(`DND All Channels ${status}`);
        dndDetails.push(`User ${action} for client ${client.name || client.email}`);
        changes.push(`DND All Channels ${status}`);
      }
      if (validatedData.dndEmail !== undefined && validatedData.dndEmail !== oldClient.dndEmail) {
        const status = validatedData.dndEmail ? "ENABLED" : "DISABLED";
        const action = validatedData.dndEmail ? "BLOCKED email communications" : "UNBLOCKED email communications";
        dndChanges.push(`Email DND ${status}`);
        dndDetails.push(`User ${action} for client ${client.name || client.email}`);
        changes.push(`Email DND ${status}`);
      }
      if (validatedData.dndSms !== undefined && validatedData.dndSms !== oldClient.dndSms) {
        const status = validatedData.dndSms ? "ENABLED" : "DISABLED";
        const action = validatedData.dndSms ? "BLOCKED SMS communications" : "UNBLOCKED SMS communications";
        dndChanges.push(`SMS DND ${status}`);
        dndDetails.push(`User ${action} for client ${client.name || client.email}`);
        changes.push(`SMS DND ${status}`);
      }
      if (validatedData.dndCalls !== undefined && validatedData.dndCalls !== oldClient.dndCalls) {
        const status = validatedData.dndCalls ? "ENABLED" : "DISABLED";
        const action = validatedData.dndCalls ? "BLOCKED call communications" : "UNBLOCKED call communications";
        dndChanges.push(`Calls DND ${status}`);
        dndDetails.push(`User ${action} for client ${client.name || client.email}`);
        changes.push(`Calls DND ${status}`);
      }

      // Create separate audit logs for DND changes due to their critical nature
      if (dndChanges.length > 0) {
        try {
        
          // Get staff name for audit log
          const staffResult = await db.select({
          id: staff.id,
          firstName: staff.firstName,
          lastName: staff.lastName,
          email: staff.email,
          phone: staff.phone,
          role: staff.role,
          departmentId: staff.departmentId,
          positionId: staff.positionId,
          status: staff.status,
          hireDate: staff.hireDate,
          lastLogin: staff.lastLogin,
          profileImage: staff.profileImage,
          bio: staff.bio,
          workHours: staff.workHours,
          timezone: staff.timezone,
          skills: staff.skills,
          isManager: staff.isManager,
          managerId: staff.managerId,
          teamIds: staff.teamIds,
          preferences: staff.preferences,
          emergencyContact: staff.emergencyContact,
          performanceGoals: staff.performanceGoals,
          createdAt: staff.createdAt,
          updatedAt: staff.updatedAt
        }).from(staff).where(eq(staff.id, currentUserId)).limit(1);
        const staffName = staffResult.length > 0 ? `${staffResult[0].firstName} ${staffResult[0].lastName}` : "System Admin";
        
        await createAuditLog(
          "updated",
          "dnd_settings",
          client.id,
          client.name || client.email,
          currentUserId,
          `CRITICAL DND CHANGE by ${staffName}: ${dndDetails.join(". ")}. Summary: ${dndChanges.join(", ")}`,
          {
            dndAll: oldClient.dndAll,
            dndEmail: oldClient.dndEmail,
            dndSms: oldClient.dndSms,
            dndCalls: oldClient.dndCalls
          },
          {
            dndAll: client.dndAll,
            dndEmail: client.dndEmail,
            dndSms: client.dndSms,
            dndCalls: client.dndCalls
          },
          req
        );

        // Also create individual audit logs for each DND change for maximum traceability
        for (const detail of dndDetails) {
          await createAuditLog(
            "updated",
            "communication_block",
            client.id,
            client.name || client.email,
            currentUserId,
            `${detail} - Action performed by ${staffName}`,
            null,
            null,
            req
          );
        }
        } catch (auditError) {
          console.error("DND audit logging failed but update was successful:", auditError);
          // Continue execution - don't fail the request for audit issues
        }
      }
      
      // Log the general update
      try {
        await createAuditLog(
        "updated",
        "contact",
        client.id,
        client.name || client.email,
        currentUserId, // SECURE: Use authenticated user ID only
        changes.length > 0 ? `Updated ${changes.join(", ")}` : "Contact record updated",
        { name: oldClient.name, email: oldClient.email, phone: oldClient.phone },
        { name: client.name, email: client.email, phone: client.phone },
        req
      );
      } catch (auditError) {
        console.error("General audit logging failed but update was successful:", auditError);
        // Continue execution - don't fail the request for audit issues
      }
      
      // Emit automation trigger for client_updated
      try {
        // Determine which fields changed
        const changedFields = Object.keys(filteredData);
        
        await emitTrigger({
          type: "client_updated",
          data: {
            ...client,
            changedFields,
            oldValues: oldClient,
          },
          context: {
            userId: currentUserId,
            timestamp: new Date(),
            metadata: { changes: changedFields },
          },
        });
      } catch (triggerError) {
        console.error("Automation trigger failed but update was successful:", triggerError);
        // Continue execution - don't fail the request for trigger issues
      }
      
      res.json(client);
    } catch (error) {
      if (error instanceof z.ZodError) {
        return res.status(400).json({ message: "Invalid data", errors: error.errors });
      }
      console.error("❌ CRITICAL: Main route error after successful database update:", error);
      console.error("❌ Error stack:", error?.stack);
      console.error("❌ Error details:", JSON.stringify(error, null, 2));
      res.status(500).json({ message: "Failed to update client" });
    }
  });

  // Archive client - SECURED
  app.patch("/api/clients/:id/archive", requireAuth(), requirePermission('clients', 'canDelete'), async (req, res) => {
    try {
      const client = await appStorage.getClient(req.params.id);
      if (!client) {
        return res.status(404).json({ message: "Client not found" });
      }

      const archivedClient = await appStorage.archiveClient(req.params.id);
      if (!archivedClient) {
        return res.status(404).json({ message: "Client not found" });
      }

      const userId = getAuthenticatedUserIdOrFail(req, res);
      if (!userId) return;

      // Log the archiving
      await createAuditLog(
        "updated",
        "contact",
        req.params.id,
        client.name || client.email,
        userId,
        `Client archived - ${client.name} (${client.email})`,
        { name: client.name, email: client.email, company: client.company },
        { isArchived: true },
        req
      );

      // Emit automation trigger for client deactivated
      try {
        await emitTrigger({
          type: "client_status_toggle",
          data: {
            ...archivedClient,
            action: "deactivated",
            reason: "archived",
          },
          context: {
            userId,
            timestamp: new Date(),
            metadata: { action: "archive" },
          },
        });
      } catch (triggerError) {
        console.error("Automation trigger failed but archive was successful:", triggerError);
      }

      res.json(archivedClient);
    } catch (error) {
      console.error("Error archiving client:", error);
      res.status(500).json({ message: "Failed to archive client" });
    }
  });

  // Reassign client tasks - SECURED
  app.post("/api/clients/:id/reassign-tasks", requireAuth(), requirePermission('clients', 'canDelete'), async (req, res) => {
    try {
      // Validate request body with Zod
      const reassignTasksSchema = z.object({
        toClientId: z.string().uuid("Target client ID must be a valid UUID")
      });

      const validation = reassignTasksSchema.safeParse(req.body);
      if (!validation.success) {
        return res.status(400).json({ 
          message: "Invalid request data", 
          errors: validation.error.errors 
        });
      }

      const { toClientId } = validation.data;

      // Prevent reassigning to the same client
      if (toClientId === req.params.id) {
        return res.status(400).json({ message: "Cannot reassign tasks to the same client" });
      }

      // Verify both clients exist
      const [fromClient, toClient] = await Promise.all([
        appStorage.getClient(req.params.id),
        appStorage.getClient(toClientId)
      ]);

      if (!fromClient) {
        return res.status(404).json({ message: "Source client not found" });
      }
      if (!toClient) {
        return res.status(404).json({ message: "Target client not found" });
      }

      const result = await appStorage.reassignClientTasks(req.params.id, toClientId);

      const userId = getAuthenticatedUserIdOrFail(req, res);
      if (!userId) return;

      // Log the reassignment
      if (result.movedCount > 0) {
        await createAuditLog(
          "updated",
          "contact",
          req.params.id,
          fromClient.name || fromClient.email,
          userId,
          `Reassigned ${result.movedCount} tasks from ${fromClient.name} to ${toClient.name}`,
          { fromClientName: fromClient.name, toClientName: toClient.name },
          { movedTasks: result.movedCount },
          req
        );
      }

      res.json(result);
    } catch (error) {
      console.error("Error reassigning client tasks:", error);
      res.status(500).json({ message: "Failed to reassign client tasks" });
    }
  });

