  app.get("/api/clients/:id/billing", requireAuth(), requirePermission('clients', 'canView'), async (req, res) => {
    try {
      const clientId = req.params.id;
      const client = await appStorage.getClient(clientId);
      if (!client) return res.status(404).json({ message: "Client not found" });

      const clientQuotes = await db.select().from(quotes)
        .where(eq(quotes.clientId, clientId))
        .orderBy(desc(quotes.updatedAt));

      const payments: any[] = [];
      let activeSubscription: any = null;
      let stripeCustomerId: string | null = null;

      for (const q of clientQuotes) {
        if (q.stripeCustomerId) stripeCustomerId = q.stripeCustomerId;

        if (q.paidAt || q.paymentStatus === 'paid' || q.paymentStatus === 'processing') {
          payments.push({
            id: q.id,
            type: 'proposal_payment',
            description: `Proposal: ${q.name || 'Untitled'}`,
            amount: q.paidAmount ? parseFloat(q.paidAmount) : 0,
            status: q.paymentStatus || 'unknown',
            method: q.paymentMethod || 'unknown',
            date: q.paidAt || q.updatedAt,
            paymentIntentId: q.paymentIntentId,
          });
        }

        if (q.stripeSubscriptionId) {
          activeSubscription = {
            subscriptionId: q.stripeSubscriptionId,
            status: q.subscriptionStatus || 'unknown',
            quoteName: q.name || 'Untitled',
            quoteId: q.id,
            monthlyAmount: q.clientBudget ? parseFloat(q.clientBudget) : 0,
          };
        }
      }

      let stripeCharges: any[] = [];
      let stripeInvoices: any[] = [];

      if (stripeCustomerId) {
        try {
          const stripe = await getStripeAsync();
          if (stripe) {
            const charges = await stripe.charges.list({
              customer: stripeCustomerId,
              limit: 50,
            });
            stripeCharges = charges.data.map(c => ({
              id: c.id,
              type: 'stripe_charge',
              description: c.description || `Charge ${c.id.slice(-8)}`,
              amount: c.amount / 100,
              status: c.status,
              method: c.payment_method_details?.type || 'unknown',
              date: new Date(c.created * 1000).toISOString(),
              receiptUrl: c.receipt_url,
              paymentIntentId: c.payment_intent || null,
            }));

            if (activeSubscription) {
              try {
                const invoices = await stripe.invoices.list({
                  customer: stripeCustomerId,
                  subscription: activeSubscription.subscriptionId,
                  limit: 50,
                });
                stripeInvoices = invoices.data.map(inv => ({
                  id: inv.id,
                  type: 'subscription_invoice',
                  description: `Invoice ${inv.number || inv.id.slice(-8)}`,
                  amount: (inv.amount_paid || 0) / 100,
                  status: inv.status,
                  date: inv.status_transitions?.paid_at
                    ? new Date(inv.status_transitions.paid_at * 1000).toISOString()
                    : new Date((inv.created || 0) * 1000).toISOString(),
                  invoiceUrl: inv.hosted_invoice_url,
                  invoicePdf: inv.invoice_pdf,
                  periodStart: inv.period_start ? new Date(inv.period_start * 1000).toISOString() : null,
                  periodEnd: inv.period_end ? new Date(inv.period_end * 1000).toISOString() : null,
                }));
              } catch (invErr) {
                console.error("[Billing] Error fetching Stripe invoices:", invErr);
              }
            }

            if (activeSubscription) {
              try {
                const sub = await stripe.subscriptions.retrieve(activeSubscription.subscriptionId);
                activeSubscription.currentPeriodStart = new Date(sub.current_period_start * 1000).toISOString();
                activeSubscription.currentPeriodEnd = new Date(sub.current_period_end * 1000).toISOString();
                activeSubscription.status = sub.status;
                activeSubscription.cancelAtPeriodEnd = sub.cancel_at_period_end;
                if (sub.items?.data?.[0]?.price?.unit_amount) {
                  activeSubscription.monthlyAmount = sub.items.data[0].price.unit_amount / 100;
                }
              } catch (subErr) {
                console.error("[Billing] Error fetching subscription details:", subErr);
              }
            }
          }
        } catch (stripeErr) {
          console.error("[Billing] Error fetching Stripe data:", stripeErr);
        }
      }

      const existingPaymentIntentIds = new Set(payments.map(p => p.paymentIntentId).filter(Boolean));
      for (const charge of stripeCharges) {
        const chargePaymentIntentId = charge.paymentIntentId;
        if (chargePaymentIntentId && existingPaymentIntentIds.has(chargePaymentIntentId)) {
          const existingIdx = payments.findIndex(p => p.paymentIntentId === chargePaymentIntentId);
          if (existingIdx >= 0 && charge.receiptUrl) {
            payments[existingIdx].receiptUrl = charge.receiptUrl;
          }
          continue;
        }
        if (!existingPaymentIntentIds.has(charge.id)) {
          payments.push(charge);
        }
      }

      payments.sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());

      const totalPaid = payments
        .filter(p => p.status === 'paid' || p.status === 'succeeded')
        .reduce((sum, p) => sum + (p.amount || 0), 0);

      res.json({
        payments,
        stripeInvoices,
        activeSubscription,
        stripeCustomerId,
        totalPaid,
      });
    } catch (error) {
      console.error("Error fetching client billing:", error);
      res.status(500).json({ message: "Failed to fetch billing data" });
    }
  });

  app.delete("/api/clients/:id", requireAuth(), requirePermission('clients', 'canDelete'), async (req, res) => {
    try {
      // Get client data before deletion for audit logging
      const client = await appStorage.getClient(req.params.id);
      if (!client) {
        return res.status(404).json({ message: "Client not found" });
      }

      // Check if the client has any related records
      const counts = await appStorage.getClientRelationsCounts(req.params.id);
      const totalRelated = counts.tasks + counts.campaigns + counts.healthScores;

      if (totalRelated > 0) {
        return res.status(409).json({ 
          message: "Cannot delete client with associated records", 
          details: `Client has ${counts.tasks} tasks, ${counts.campaigns} campaigns, and ${counts.healthScores} health scores. Archive the client or reassign tasks first.`,
          counts 
        });
      }
      
      const deleted = await appStorage.deleteClient(req.params.id);
      if (!deleted) {
        return res.status(404).json({ message: "Client not found" });
      }
      
      const userId = getAuthenticatedUserIdOrFail(req, res);
      if (!userId) return; // getAuthenticatedUserIdOrFail already sent 401 response
      
      // Log the deletion
      await createAuditLog(
        "deleted",
        "contact",
        req.params.id,
        client.name || client.email,
        userId, // SECURE: Use authenticated user ID only
        `Contact record permanently deleted - ${client.name} (${client.email})`,
        { name: client.name, email: client.email, company: client.company },
        null,
        req
      );
      
      res.status(204).send();
    } catch (error) {
      console.error("Error deleting client:", error);
      
      // Handle PostgreSQL foreign key constraint errors as fallback
      if (error?.code === '23503' && error?.constraint && error.constraint.includes('_fk')) {
        try {
          const counts = await appStorage.getClientRelationsCounts(req.params.id);
          return res.status(409).json({ 
            message: "Cannot delete client with associated records", 
            details: `Client has ${counts.tasks} tasks, ${counts.campaigns} campaigns, and ${counts.healthScores} health scores. Archive the client or reassign tasks first.`,
            counts
          });
        } catch (countError) {
          console.error("Error getting counts for constraint error:", countError);
        }
      }
      
      res.status(500).json({ message: "Failed to delete client" });
    }
  });

