  app.put("/api/health-scores/:id", requireAuth(), requirePermission('clients', 'canEdit'), async (req, res) => {
    try {
      // Get the old health score data first for audit logging
      const oldHealthScore = await appStorage.getClientHealthScore(req.params.id);
      if (!oldHealthScore) {
        return res.status(404).json({ message: "Health score not found" });
      }
      
      const validatedData = inputClientHealthScoreSchema.partial().parse(req.body);
      
      // Recalculate scoring if any scoring fields are being updated
      let updatedData = { ...validatedData };
      const scoringFields = ['goals', 'fulfillment', 'relationship', 'clientActions', 'paymentStatus'];
      const hasAnyScoreFieldUpdate = scoringFields.some(field => validatedData.hasOwnProperty(field));
      
      if (hasAnyScoreFieldUpdate) {
        // Use updated values if provided, otherwise use existing values
        const goals = validatedData.goals || oldHealthScore.goals;
        const fulfillment = validatedData.fulfillment || oldHealthScore.fulfillment;
        const relationship = validatedData.relationship || oldHealthScore.relationship;
        const clientActions = validatedData.clientActions || oldHealthScore.clientActions;
        const paymentStatus = (validatedData as any).paymentStatus || (oldHealthScore as any).paymentStatus || 'Current';
        
        // Load health settings and calculate metrics
        const healthSettingsRow2 = await db.select().from(taskSettings).where(eq(taskSettings.settingKey, "client_health_config"));
        const healthSettings2 = healthSettingsRow2.length > 0 ? healthSettingsRow2[0].settingValue as HealthSettings : undefined;
        const { totalScore, averageScore, healthIndicator } = calculateHealthMetrics({
          goals,
          fulfillment,
          relationship,
          clientActions,
          paymentStatus
        }, healthSettings2);
        
        updatedData = {
          ...updatedData,
          totalScore,
          averageScore,
          healthIndicator
        };
      }
      
      const healthScore = await appStorage.updateClientHealthScore(req.params.id, updatedData);
      
      const userId = getAuthenticatedUserIdOrFail(req, res);
      if (!userId) return; // getAuthenticatedUserIdOrFail already sent 401 response
      
      // Log the update
      await createAuditLog(
        "updated",
        "client_health_score",
        healthScore.id,
        `Health Score for ${healthScore.weekStartDate}`,
        userId, // SECURE: Use authenticated user ID only
        `Health score updated for week ${healthScore.weekStartDate}`,
        { totalScore: oldHealthScore.totalScore, averageScore: oldHealthScore.averageScore, healthIndicator: oldHealthScore.healthIndicator },
        { totalScore: healthScore.totalScore, averageScore: healthScore.averageScore, healthIndicator: healthScore.healthIndicator },
        req
      );
      
      // Emit automation trigger for health score changed
      try {
        if (oldHealthScore.healthIndicator !== healthScore.healthIndicator) {
          const direction = (healthScore.totalScore || 0) > (oldHealthScore.totalScore || 0) ? "improved" : "declined";
          const scoreDelta = Math.abs((healthScore.totalScore || 0) - (oldHealthScore.totalScore || 0));
          
          await emitTrigger({
            type: "client_health_score_changed",
            data: {
              id: healthScore.clientId,
              clientId: healthScore.clientId,
              threshold: healthScore.healthIndicator,
              direction,
              scoreDelta,
              oldScore: oldHealthScore.totalScore,
              newScore: healthScore.totalScore,
              oldIndicator: oldHealthScore.healthIndicator,
              newIndicator: healthScore.healthIndicator,
            },
            context: {
              userId,
              timestamp: new Date(),
              metadata: { weekStartDate: healthScore.weekStartDate },
            },
          });
        }
      } catch (triggerError) {
        console.error("Automation trigger failed but health score update was successful:", triggerError);
      }

      // Notify client followers about the health score update (only if indicator changed)
      try {
        if (oldHealthScore.healthIndicator !== healthScore.healthIndicator) {
          const clientData = await db.select().from(clients).where(eq(clients.id, healthScore.clientId)).limit(1);
          const clientRecord = clientData[0];
          
          if (clientRecord && clientRecord.followers && clientRecord.followers.length > 0) {
            const clientName = clientRecord.company || clientRecord.name || 'Unknown Client';
            const userInfo = await db.select().from(staff).where(eq(staff.id, userId)).limit(1);
            const authorName = userInfo[0] ? `${userInfo[0].firstName} ${userInfo[0].lastName}` : 'A team member';
            const direction = (healthScore.totalScore || 0) > (oldHealthScore.totalScore || 0) ? 'improved' : 'declined';
            
            // Create notifications for each follower (except the author)
            for (const followerId of clientRecord.followers) {
              if (followerId !== userId) {
                await db.insert(notifications).values({
                  userId: followerId,
                  type: "client_health_change",
                  title: `Health status ${direction} for followed client`,
                  message: `${clientName}'s health status ${direction} from ${oldHealthScore.healthIndicator} to ${healthScore.healthIndicator}`,
                  entityType: "client",
                  entityId: healthScore.clientId,
                  priority: healthScore.healthIndicator === 'critical' || healthScore.healthIndicator === 'at_risk' ? 'high' : 'normal',
                  actionUrl: `/clients/${healthScore.clientId}`,
                  actionText: "View Client",
                  metadata: {
                    healthScoreId: healthScore.id,
                    oldIndicator: oldHealthScore.healthIndicator,
                    newIndicator: healthScore.healthIndicator,
                    direction: direction,
                    authorId: userId,
                    authorName: authorName
                  }
                });
              }
            }
          }
        }
      } catch (notificationError) {
        console.error("Failed to create follower health change notifications:", notificationError);
        // Don't fail the request if notification creation fails
      }
      
      res.json(healthScore);
    } catch (error) {
      if (error instanceof z.ZodError) {
        return res.status(400).json({ message: "Invalid data", errors: error.errors });
      }
      
      console.error("Error updating health score:", error);
      const errorMessage = error instanceof Error ? error.message : "Unknown error";
      res.status(500).json({ message: "Failed to update health score", error: errorMessage });
    }
  });

