  app.delete("/api/staff/:id", requireAuth(), requirePermission('staff', 'canDelete'), async (req, res) => {
    try {
      const userId = getAuthenticatedUserIdOrFail(req, res);
      if (!userId) return; // getAuthenticatedUserIdOrFail already sent 401 response
      
      // Get staff data before deletion for audit logging
      const [staffToDelete] = await db.select({
        id: staff.id,
        firstName: staff.firstName,
        lastName: staff.lastName,
        email: staff.email,
        phone: staff.phone,
        roleId: staff.roleId,
        profileImagePath: staff.profileImagePath,
        hireDate: staff.hireDate,
        department: staff.department,
        position: staff.position,
        managerId: staff.managerId,
        isActive: staff.isActive,
        createdAt: staff.createdAt,
        updatedAt: staff.updatedAt
      }).from(staff).where(eq(staff.id, req.params.id));
      if (!staffToDelete) {
        return res.status(404).json({ message: "Staff member not found" });
      }
      
      const deletedEmail = `deleted_${Date.now()}_${staffToDelete.email}`;
      const [deletedStaff] = await db
        .update(staff)
        .set({ isActive: false, email: deletedEmail })
        .where(eq(staff.id, req.params.id))
        .returning();
      
      if (!deletedStaff) {
        return res.status(404).json({ message: "Staff member not found" });
      }

      // Clean up system-generated calendar events (anniversaries and birthdays) for this staff member
      try {
        const deletedEvents = await db
          .delete(calendarAppointments)
          .where(
            and(
              eq(calendarAppointments.assignedTo, req.params.id),
              eq(calendarAppointments.bookingSource, 'system')
            )
          )
          .returning();
        
        console.log(`Cleaned up ${deletedEvents.length} system calendar events for deactivated staff member ${staffToDelete.firstName} ${staffToDelete.lastName}`);
      } catch (cleanupError) {
        console.error('Error cleaning up calendar events for deactivated staff:', cleanupError);
        // Don't fail the staff deletion if calendar cleanup fails - just log the error
      }
      
      // Deactivate and clear the auth_users record so the email can be reused
      try {
        const [authUserRecord] = await db.select().from(authUsers).where(eq(authUsers.userId, req.params.id));
        if (authUserRecord) {
          // Modify the email to free it up for reuse, and deactivate the account
          const deletedEmail = `deleted_${Date.now()}_${authUserRecord.email}`;
          await db.update(authUsers)
            .set({ 
              isActive: false, 
              email: deletedEmail,
              passwordHash: '', // Clear password hash for security
              passwordResetToken: null,
              passwordResetExpires: null
            })
            .where(eq(authUsers.userId, req.params.id));
          
          // Also remove from user_roles to revoke permissions
          await db.delete(userRoles).where(eq(userRoles.userId, authUserRecord.id));
          
          console.log(`Deactivated auth record and cleared email for deleted staff member ${staffToDelete.firstName} ${staffToDelete.lastName}`);
        }
      } catch (authCleanupError) {
        console.error('Error cleaning up auth record for deactivated staff:', authCleanupError);
        // Don't fail the staff deletion if auth cleanup fails - just log the error
      }
      
      // Log the deletion
      await createAuditLog(
        "deleted",
        "staff",
        req.params.id,
        `${staffToDelete.firstName} ${staffToDelete.lastName}`,
        userId, // SECURE: Use authenticated user ID only
        `Staff member deactivated - ${staffToDelete.firstName} ${staffToDelete.lastName} (${staffToDelete.email})`,
        { firstName: staffToDelete.firstName, lastName: staffToDelete.lastName, email: staffToDelete.email, isActive: true },
        { isActive: false },
        req
      );
      
      res.json({ success: true });
    } catch (error) {
      console.error('Error deleting staff:', error);
      res.status(500).json({ message: "Failed to delete staff member" });
    }
  });


  // ========================
