  // HR Org Structure Hierarchy API - Uses Team Positions (unified with Settings > Staff > Teams)
  app.get("/api/org-structure", requireAuth(), requirePermission('hr', 'canView'), async (req, res) => {
    try {
      // Fetch team positions that are explicitly added to the org chart
      const allTeamPositions = await appStorage.getTeamPositions();
      const positions = allTeamPositions.filter(p => p.inOrgChart === true);
      
      // Build hierarchical structure - positions only
      const buildTree = () => {
        const rootNodes: any[] = [];
        
        // Create position nodes (map teamPosition fields to expected format)
        const posMap = new Map();
        positions.forEach(pos => {
          posMap.set(pos.id, { 
            id: pos.id,
            name: pos.label, // teamPositions use 'label' instead of 'name'
            description: pos.description,
            type: 'position', 
            orderIndex: pos.orgChartOrder || 0,
            parentPositionId: pos.parentPositionId,
            isActive: pos.isActive,
            children: [] 
          });
        });
        
        // Build position hierarchy
        positions.forEach(pos => {
          const node = posMap.get(pos.id);
          
          if (pos.parentPositionId && posMap.has(pos.parentPositionId)) {
            // Position nested under another position
            posMap.get(pos.parentPositionId).children.push(node);
          } else if (!pos.parentPositionId) {
            // Root-level position (no parent)
            rootNodes.push(node);
          }
        });
        
        // Sort all nodes by orderIndex recursively
        const sortByOrder = (nodes: any[]) => {
          nodes.sort((a, b) => (a.orderIndex || 0) - (b.orderIndex || 0));
          nodes.forEach(node => {
            if (node.children && node.children.length > 0) {
              sortByOrder(node.children);
            }
          });
        };
        sortByOrder(rootNodes);
        
        return rootNodes;
      };
      
      const tree = buildTree();
      res.json(tree);
    } catch (error) {
      console.error('Error fetching org structure:', error);
      res.status(500).json({ message: "Failed to fetch org structure" });
    }
  });
  
  app.patch("/api/departments/:id/hierarchy", requireAuth(), requirePermission('departments', 'canEdit'), async (req, res) => {
    try {
      const { parentDepartmentId, orderIndex } = req.body;
      console.log(`[HIERARCHY UPDATE] Department ${req.params.id}: parentDepartmentId=${parentDepartmentId}, orderIndex=${orderIndex}`);
      
      // Validate no circular reference
      if (parentDepartmentId) {
        let currentParent = parentDepartmentId;
        const visited = new Set([req.params.id]);
        while (currentParent) {
          if (visited.has(currentParent)) {
            return res.status(400).json({ message: "Circular reference detected" });
          }
          visited.add(currentParent);
          const parent = await appStorage.getDepartment(currentParent);
          currentParent = parent?.parentDepartmentId || null;
        }
      }
      
      const updated = await appStorage.updateDepartment(req.params.id, {
        parentDepartmentId,
        orderIndex: orderIndex ?? 0
      });
      
      console.log(`[HIERARCHY UPDATE] Updated department:`, JSON.stringify(updated));
      
      if (!updated) {
        return res.status(404).json({ message: "Department not found" });
      }
      
      res.json(updated);
    } catch (error) {
      console.error('Error updating department hierarchy:', error);
      res.status(500).json({ message: "Failed to update department hierarchy" });
    }
  });
  
  app.patch("/api/positions/:id/hierarchy", requireAuth(), requirePermission('departments', 'canEdit'), async (req, res) => {
    try {
      const { parentPositionId, destinationIndex, departmentId } = req.body;
      const positionId = req.params.id;
      
      // Get the current position to know its current parent
      const currentPosition = await appStorage.getPosition(positionId);
      if (!currentPosition) {
        return res.status(404).json({ message: "Position not found" });
      }
      
      const sourceParentId = currentPosition.parentPositionId;
      const destParentId = parentPositionId || null;
      const isChangingParent = sourceParentId !== destParentId;
      
      // Validate no circular reference
      if (destParentId) {
        let currentParent = destParentId;
        const visited = new Set([positionId]);
        while (currentParent) {
          if (visited.has(currentParent)) {
            return res.status(400).json({ message: "Circular reference detected" });
          }
          visited.add(currentParent);
          const parent = await appStorage.getPosition(currentParent);
          currentParent = parent?.parentPositionId || null;
        }
      }
      
      // Wrap in transaction for atomicity
      await db.transaction(async (tx) => {
        // Get all positions for reindexing
        const allPositions = await tx.select().from(positions);
        
        // 1. Reindex source parent's siblings (if changing parents)
        if (isChangingParent && sourceParentId !== undefined) {
          const sourceSiblings = allPositions
            .filter(p => p.id !== positionId && p.parentPositionId === sourceParentId)
            .sort((a, b) => (a.orderIndex || 0) - (b.orderIndex || 0));
          
          for (let i = 0; i < sourceSiblings.length; i++) {
            if (sourceSiblings[i].orderIndex !== i) {
              await tx.update(positions)
                .set({ orderIndex: i })
                .where(eq(positions.id, sourceSiblings[i].id));
            }
          }
        }
        
        // 2. Find destination siblings (excluding the moved position)
        const destSiblings = allPositions
          .filter(p => p.id !== positionId && p.parentPositionId === destParentId)
          .sort((a, b) => (a.orderIndex || 0) - (b.orderIndex || 0));
        
        // 3. Calculate target index and update moved position
        const targetIndex = Math.max(0, Math.min(destinationIndex ?? 0, destSiblings.length));
        
        const updateData: any = {
          parentPositionId: destParentId,
          orderIndex: targetIndex
        };
        
        if (departmentId !== undefined) {
          updateData.departmentId = departmentId;
        }
        
        await tx.update(positions)
          .set(updateData)
          .where(eq(positions.id, positionId));
        
        // 4. Reindex destination siblings to make room
        for (let i = 0; i < destSiblings.length; i++) {
          const sibling = destSiblings[i];
          const newOrderIndex = i >= targetIndex ? i + 1 : i;
          
          if (sibling.orderIndex !== newOrderIndex) {
            await tx.update(positions)
              .set({ orderIndex: newOrderIndex })
              .where(eq(positions.id, sibling.id));
          }
        }
      });
      
      // Get the updated position to return
      const updated = await appStorage.getPosition(positionId);
      res.json(updated);
    } catch (error) {
      console.error('Error updating position hierarchy:', error);
      res.status(500).json({ message: "Failed to update position hierarchy" });
    }
  });

