  // ============== TWILIO VOIP CALLING ENDPOINTS ==============

  // Generate Twilio Voice access token for browser-based calling
  app.get("/api/integrations/twilio/voice-token", requireAuth(), async (req, res) => {
    try {
      const userId = getAuthenticatedUserId(req);
      if (!userId) {
        return res.status(401).json({ message: "Unauthorized" });
      }

      // Get active Twilio integration
      const [integration] = await db
        .select()
        .from(smsIntegrations)
        .where(and(
          eq(smsIntegrations.provider, 'twilio'),
          eq(smsIntegrations.isActive, true)
        ))
        .limit(1);

      if (!integration) {
        return res.status(400).json({ 
          message: "No active Twilio integration found. Please configure Twilio in Settings > Integrations." 
        });
      }

      // Check for TwiML App SID in environment
      const twimlAppSid = process.env.TWILIO_TWIML_APP_SID;
      if (!twimlAppSid) {
        return res.status(400).json({ 
          message: "Twilio TwiML App not configured. Please set TWILIO_TWIML_APP_SID environment variable." 
        });
      }

      // Check for API credentials
      const apiKeySid = process.env.TWILIO_API_KEY_SID;
      const apiKeySecret = process.env.TWILIO_API_KEY_SECRET;
      if (!apiKeySid || !apiKeySecret) {
        return res.status(400).json({ 
          message: "Twilio API credentials not configured. Please set TWILIO_API_KEY_SID and TWILIO_API_KEY_SECRET." 
        });
      }

      // Generate access token for Voice SDK
      const AccessToken = twilio.jwt.AccessToken;
      const VoiceGrant = AccessToken.VoiceGrant;

      const accessToken = new AccessToken(
        integration.accountSid,
        apiKeySid,
        apiKeySecret,
        { identity: userId }
      );

      // Create a Voice grant for this token
      const voiceGrant = new VoiceGrant({
        outgoingApplicationSid: twimlAppSid,
        incomingAllow: false
      });

      accessToken.addGrant(voiceGrant);

      res.json({
        token: accessToken.toJwt(),
        identity: userId,
        callerIdNumber: integration.phoneNumber,
        expiresIn: 3600
      });
    } catch (error) {
      console.error('Error generating voice token:', error);
      res.status(500).json({ 
        message: "Failed to generate voice token",
        error: (error as Error).message
      });
    }
  });

  // TwiML webhook for outbound calls - Twilio calls this to get call instructions
  app.post("/api/integrations/twilio/voice-twiml", async (req, res) => {
    try {
      const { To, From, CallerId } = req.body;
      
      console.log('[TwiML] Outbound call request:', { To, From, CallerId });

      // Get the caller ID (phone number to show)
      const [integration] = await db
        .select()
        .from(smsIntegrations)
        .where(and(
          eq(smsIntegrations.provider, 'twilio'),
          eq(smsIntegrations.isActive, true)
        ))
        .limit(1);

      const callerIdNumber = CallerId || integration?.phoneNumber || From;

      // Build TwiML response
      const VoiceResponse = twilio.twiml.VoiceResponse;
      const twiml = new VoiceResponse();

      if (To) {
        const dial = twiml.dial({ callerId: callerIdNumber });
        if (To.startsWith('sip:')) {
          dial.sip(To);
        } else {
          dial.number(To);
        }
      } else {
        twiml.say('No phone number specified for outbound call.');
      }

      res.type('text/xml');
      res.send(twiml.toString());
    } catch (error) {
      console.error('Error generating TwiML:', error);
      
      const VoiceResponse = twilio.twiml.VoiceResponse;
      const twiml = new VoiceResponse();
      twiml.say('An error occurred while connecting your call. Please try again.');
      
      res.type('text/xml');
      res.send(twiml.toString());
    }
  });

  // Incoming SMS webhook - Twilio POSTs here when someone replies to an SMS
  app.post("/api/webhooks/twilio/sms", async (req, res) => {
    try {
      const { From, To, Body, MessageSid, NumMedia } = req.body;
      
      console.log('[SMS Webhook] Incoming SMS:', { From, To, Body: Body?.substring(0, 50), MessageSid, NumMedia });
      
      if (!From || !Body) {
        console.warn('[SMS Webhook] Missing From or Body in webhook payload');
        const MessagingResponse = twilio.twiml.MessagingResponse;
        const twiml = new MessagingResponse();
        res.type('text/xml');
        return res.send(twiml.toString());
      }
      
      // Normalize the sender phone number for matching (strip formatting)
      const normalizedFrom = From.replace(/[^\d+]/g, '');
      
      // Try to match the sender to a client by phone number
      const allClients = await db.select({ id: clients.id, name: clients.name, phone: clients.phone, company: clients.company }).from(clients);
      
      let matchedClient = null;
      for (const c of allClients) {
        if (c.phone) {
          const normalizedClientPhone = c.phone.replace(/[^\d+]/g, '');
          // Match if either ends with the other (handles +1 prefix differences)
          if (normalizedFrom === normalizedClientPhone ||
              normalizedFrom.endsWith(normalizedClientPhone.replace(/^\+?1/, '')) ||
              normalizedClientPhone.endsWith(normalizedFrom.replace(/^\+?1/, ''))) {
            matchedClient = c;
            break;
          }
        }
      }
      
      console.log('[SMS Webhook] Matched client:', matchedClient ? { id: matchedClient.id, name: matchedClient.name } : 'No match');
      
      // Find a system user to attribute the log to (use the first admin)
      let systemUserId: string | null = null;
      try {
        const [adminUser] = await db
          .select({ id: staff.id })
          .from(staff)
          .limit(1);
        systemUserId = adminUser?.id || null;
      } catch (e) {
        console.error('[SMS Webhook] Error finding system user:', e);
      }
      
      // Create audit log for the incoming SMS
      const entityName = matchedClient 
        ? `SMS from ${matchedClient.name || matchedClient.company || From}` 
        : `SMS from ${From}`;
      
      try {
        await createAuditLog(
          "created",
          "sms",
          MessageSid || `incoming-${Date.now()}`,
          entityName,
          systemUserId || "system",
          `Received SMS from ${From}: ${Body.substring(0, 100)}${Body.length > 100 ? '...' : ''}`,
          null,
          { 
            to: To, 
            from: From, 
            message: Body, 
            clientId: matchedClient?.id || null, 
            status: 'received', 
            provider: 'twilio',
            direction: 'inbound',
            messageSid: MessageSid,
            numMedia: NumMedia ? parseInt(NumMedia) : 0
          },
          null
        );
        console.log('[SMS Webhook] Successfully logged incoming SMS from:', From);
      } catch (auditError) {
        console.error('[SMS Webhook] Failed to create audit log:', auditError);
      }
      
      // Respond with empty TwiML (acknowledge receipt, no auto-reply)
      const MessagingResponse = twilio.twiml.MessagingResponse;
      const twiml = new MessagingResponse();
      res.type('text/xml');
      res.send(twiml.toString());
    } catch (error) {
      console.error('[SMS Webhook] Error processing incoming SMS:', error);
      // Always respond with valid TwiML even on error
      const MessagingResponse = twilio.twiml.MessagingResponse;
      const twiml = new MessagingResponse();
      res.type('text/xml');
      res.send(twiml.toString());
    }
  });

  // Twilio SMS status callback webhook — updates audit log status when delivery status changes
  app.post("/api/webhooks/twilio/status", async (req, res) => {
    try {
      const { MessageSid, MessageStatus, ErrorCode, ErrorMessage } = req.body;
      
      console.log('[Twilio Status Callback]', { MessageSid, MessageStatus, ErrorCode, ErrorMessage });
      
      if (!MessageSid || !MessageStatus) {
        return res.sendStatus(200);
      }
      
      // Find the audit log entry for this message SID (entityId = message SID)
      const [existingLog] = await db
        .select()
        .from(auditLogs)
        .where(and(
          eq(auditLogs.entityType, 'sms'),
          eq(auditLogs.entityId, MessageSid)
        ))
        .limit(1);
      
      if (existingLog) {
        const currentValues = (existingLog.newValues as any) || {};
        const updatedValues = {
          ...currentValues,
          status: MessageStatus,
          ...(ErrorCode ? { errorCode: ErrorCode } : {}),
          ...(ErrorMessage ? { errorMessage: ErrorMessage } : {}),
          statusUpdatedAt: new Date().toISOString(),
        };
        
        await db
          .update(auditLogs)
          .set({ newValues: updatedValues })
          .where(eq(auditLogs.id, existingLog.id));
        
        console.log(`[Twilio Status Callback] Updated audit log ${existingLog.id} status: ${currentValues.status} → ${MessageStatus}`);
      } else {
        console.log(`[Twilio Status Callback] No audit log found for MessageSid: ${MessageSid}`);
      }
      
      res.sendStatus(200);
    } catch (error) {
      console.error('[Twilio Status Callback] Error:', error);
      res.sendStatus(200);
    }
  });

