  // POST /api/task-intake/submit - Submit intake form and create task
  app.post("/api/task-intake/submit", requireAuth(), async (req, res) => {
    try {
      const staffId = req.session?.userId;
      if (!staffId) {
        return res.status(401).json({ error: "Authentication required" });
      }

      const { formId, answers, visibleSectionIds, parentTaskId, categoryId: userSelectedCategoryId, isRecurring, recurringInterval, recurringUnit, recurringEndType, recurringEndDate, recurringEndOccurrences } = req.body;

      if (!formId || !answers || !visibleSectionIds) {
        return res.status(400).json({ error: "Missing required fields: formId, answers, visibleSectionIds" });
      }

      // Handle subtask creation - get parent task info for level calculation
      let subtaskLevel = 0;
      let inheritedClientId: string | null = null;
      let inheritedProjectId: string | null = null;
      if (parentTaskId) {
        console.log("[TaskIntake] Looking up parent task:", parentTaskId);
        const parentResults = await db.select({
          level: tasks.level,
          clientId: tasks.clientId,
          projectId: tasks.projectId,
        })
          .from(tasks)
          .where(eq(tasks.id, parentTaskId));
        
        console.log("[TaskIntake] Parent task query returned:", parentResults.length, "results");
        const parentTask = parentResults[0];
        if (parentTask) {
          subtaskLevel = (parentTask.level || 0) + 1;
          inheritedClientId = parentTask.clientId;
          inheritedProjectId = parentTask.projectId;
          console.log("[TaskIntake] Parent task found - level:", subtaskLevel, "clientId:", inheritedClientId, "projectId:", inheritedProjectId);
        } else {
          console.warn("[TaskIntake] Parent task not found:", parentTaskId);
        }
      }
      // Step A: Validate submission
      // Get all questions for the form
      const questions = await db.select()
        .from(taskIntakeQuestions)
        .where(eq(taskIntakeQuestions.formId, formId));

      // Build a map for easy lookup
      const questionMap = new Map(questions.map(q => [q.id, q]));

      // Helper function to check if a question is hidden by hideWhen condition
      const isQuestionHiddenByCondition = (question: any): boolean => {
        const settings = question.settings as Record<string, any> | null;
        if (!settings?.hideWhen) return false;
        
        const { triggerQuestionId, requiredValues } = settings.hideWhen;
        if (!triggerQuestionId || !Array.isArray(requiredValues)) return false;
        
        const triggerAnswer = answers[triggerQuestionId];
        if (triggerAnswer === undefined || triggerAnswer === null) return false;
        
        const answerValues = Array.isArray(triggerAnswer) ? triggerAnswer : [String(triggerAnswer)];
        return requiredValues.some((val: string) => answerValues.includes(val));
      };

      // Check required fields in visible sections (respecting question-level visibility)
      const errors: { questionId: string; message: string }[] = [];
      for (const question of questions) {
        // Only validate questions in visible sections that are not hidden by hideWhen
        if (question.sectionId && visibleSectionIds.includes(question.sectionId)) {
          // Skip validation for questions hidden by hideWhen condition
          if (isQuestionHiddenByCondition(question)) {
            continue;
          }
          
          const answer = answers[question.id];
          
          if (question.isRequired) {
            if (answer === undefined || answer === null || answer === '' || 
                (Array.isArray(answer) && answer.length === 0)) {
              errors.push({ questionId: question.id, message: `Required field: ${question.questionText}` });
            }
          }

          // Validate format based on question type
          if (answer !== undefined && answer !== null && answer !== '') {
            if (question.questionType === 'number' && isNaN(Number(answer))) {
              errors.push({ questionId: question.id, message: 'Must be a valid number' });
            }
            if (question.questionType === 'date' && isNaN(Date.parse(answer))) {
              errors.push({ questionId: question.id, message: 'Must be a valid date' });
            }
            if (question.questionType === 'url' && answer && !/^https?:\/\/.+/.test(answer)) {
              errors.push({ questionId: question.id, message: 'Must be a valid URL (starting with http:// or https://)' });
            }
          }
        }
      }

      if (errors.length > 0) {
        return res.status(400).json({ error: "Validation failed", errors });
      }

      // Check for duplicate submission (same task name + user in last 60 seconds)
      const taskNameQuestion = questions.find(q => q.internalLabel?.toLowerCase() === 'task_name');
      const taskNameAnswer = taskNameQuestion ? answers[taskNameQuestion.id] : null;

      if (taskNameAnswer) {
        const recentSubmissions = await db.select()
          .from(taskIntakeSubmissions)
          .innerJoin(taskIntakeAnswers, eq(taskIntakeAnswers.submissionId, taskIntakeSubmissions.id))
          .where(
            and(
              eq(taskIntakeSubmissions.submittedBy, staffId),
              eq(taskIntakeSubmissions.formId, formId),
              gte(taskIntakeSubmissions.submittedAt, new Date(Date.now() - 60000))
            )
          )
          .limit(1);

        if (recentSubmissions.length > 0) {
          // Check if any of those have the same task name
          for (const sub of recentSubmissions) {
            if (sub.task_intake_answers.answerValue === taskNameAnswer && 
                sub.task_intake_answers.questionId === taskNameQuestion?.id) {
              return res.status(400).json({ 
                error: "Duplicate submission detected. Please wait before submitting again." 
              });
            }
          }
        }
      }

      // Step B: Create submission record
      const [submission] = await db.insert(taskIntakeSubmissions)
        .values({
          formId,
          submittedBy: staffId,
          status: 'pending',
        })
        .returning();

      // Create answer records
      const answerRecords = [];
      for (const [questionId, answerValue] of Object.entries(answers)) {
        const question = questionMap.get(questionId);
        if (question) {
          const wasVisible = question.sectionId ? visibleSectionIds.includes(question.sectionId) : true;
          answerRecords.push({
            submissionId: submission.id,
            questionId,
            sectionId: question.sectionId,
            answerValue: typeof answerValue === 'object' ? JSON.stringify(answerValue) : String(answerValue || ''),
            wasVisible,
          });
        }
      }

      if (answerRecords.length > 0) {
        await db.insert(taskIntakeAnswers).values(answerRecords);
      }

      // Step C: Extract key fields for task
      const getAnswerByLabel = (label: string): string | null => {
        const q = questions.find(q => { const cleanLabel = q.internalLabel?.toLowerCase().replace(/^trigger\s*-\s*/, ''); return cleanLabel === label.toLowerCase() || q.internalLabel?.toLowerCase() === label.toLowerCase(); });
        if (!q) return null;
        const val = answers[q.id];
        return val !== undefined ? (typeof val === 'object' ? JSON.stringify(val) : String(val)) : null;
      };

      const taskTitle = getAnswerByLabel('task_name') || 'Untitled Task';
      console.log("[TaskIntake] Creating task with title:", taskTitle, "| task_name question found:", !!questions.find(q => q.internalLabel?.toLowerCase() === "task_name"), "| Answer keys count:", Object.keys(answers).length);
      const clientId = getAnswerByLabel('client_select');
      const dueDateStr = getAnswerByLabel('due_date');
      const priorityLevel = getAnswerByLabel('priority_level') || 'normal';
      const department = getAnswerByLabel('department');

      // Map priority level to task priority using imported function
      const priority = mapPriority(priorityLevel);

      // Get description from the description_additional_notes field
      const taskDescription = getAnswerByLabel('description_additional_notes') || '';

      // Step D: Evaluate assignment rules
      const assignmentResult = await evaluateAssignmentRules(formId, answers);
      console.log("[TaskIntake] Assignment rules result:", assignmentResult);
      // Special handling for Personal Tasks - auto-assign to the person creating the task
      const taskScope = getAnswerByLabel('task_scope');
      const isPersonalTask = taskScope?.toLowerCase().includes('personal');
      if (isPersonalTask) {
        console.log("[TaskIntake] Personal Task detected - auto-assigning to creator:", staffId);
        assignmentResult.assignToUserId = staffId;
      }

      // Auto-assign sub-tasks to the person who created them
      if (parentTaskId) {
        console.log("[TaskIntake] Sub-task detected - auto-assigning to creator:", staffId);
        assignmentResult.assignToUserId = staffId;
      }

      // Step E: Validate references and create the task
      const resolvedCategoryId = assignmentResult.categoryId || (userSelectedCategoryId && userSelectedCategoryId !== '__none__' ? userSelectedCategoryId : null);
      const resolvedAssignedTo = assignmentResult.assignToUserId || null;
      const resolvedClientId = parentTaskId ? inheritedClientId : (clientId && clientId !== 'no_client' ? clientId : null);
      const resolvedProjectId = parentTaskId ? inheritedProjectId : null;
      
      console.log("[TaskIntake] Creating task:", { 
        title: taskTitle, parentTaskId, level: parentTaskId ? subtaskLevel : 0,
        clientId: resolvedClientId, projectId: resolvedProjectId,
        categoryId: resolvedCategoryId, assignedTo: resolvedAssignedTo,
      });
      
      const [newTask] = await db.insert(tasks)
        .values({
          title: taskTitle,
          description: taskDescription,
          status: 'todo',
          priority,
          clientId: resolvedClientId,
          startDate: (() => { const now = new Date(); const eastern = new Date(now.toLocaleString('en-US', { timeZone: 'America/New_York' })); eastern.setHours(0, 0, 0, 0); return eastern; })(),
          dueDate: dueDateStr ? new Date(dueDateStr) : null,
          assignedTo: resolvedAssignedTo,
          categoryId: resolvedCategoryId,
          tags: assignmentResult.tags.length > 0 ? assignmentResult.tags : undefined,
          parentTaskId: parentTaskId || null,
          level: parentTaskId ? subtaskLevel : 0,
          projectId: resolvedProjectId,
          isRecurring: isRecurring || false,
          recurringInterval: isRecurring ? (recurringInterval || 1) : undefined,
          recurringUnit: isRecurring ? (recurringUnit || "days") : undefined,
          recurringEndType: isRecurring ? (recurringEndType || "never") : undefined,
          recurringEndDate: isRecurring && recurringEndType === "on_date" && recurringEndDate ? new Date(recurringEndDate) : undefined,
          recurringEndOccurrences: isRecurring && recurringEndType === "after_occurrences" ? (recurringEndOccurrences || 10) : undefined,
        })
        .returning();

      // Step F: Process upload-type answers and create task attachments
      const uploadQuestions = questions.filter(q => q.questionType === 'upload');
      for (const uploadQ of uploadQuestions) {
        const uploadAnswer = answers[uploadQ.id];
        if (uploadAnswer) {
          try {
            const uploadedFiles = typeof uploadAnswer === 'string' ? JSON.parse(uploadAnswer) : uploadAnswer;
            if (Array.isArray(uploadedFiles)) {
              const { ObjectStorageService } = await import("./objectStorage");
              const objectStorageService = new ObjectStorageService();
              for (const file of uploadedFiles) {
                if (file.url && file.name) {
                  const normalizedUrl = objectStorageService.normalizeObjectEntityPath(file.url);
                  await db.insert(taskAttachments).values({
                    taskId: newTask.id,
                    fileName: file.name,
                    fileType: file.type || 'application/octet-stream',
                    fileSize: file.size || 0,
                    fileUrl: normalizedUrl,
                    uploadedBy: staffId,
                  });
                  console.log(`[TaskIntake] Created attachment for task ${newTask.id}: ${file.name}`);
                }
              }
            }
          } catch (uploadErr) {
            console.error("[TaskIntake] Error processing upload attachments:", uploadErr);
          }
        }
      }

      // Step G: Update submission with taskId
      await db.update(taskIntakeSubmissions)
        .set({ 
          taskId: newTask.id,
          status: 'task_created',
          updatedAt: new Date(),
        })
        .where(eq(taskIntakeSubmissions.id, submission.id));

      // Step H: Return response
      res.json({
        success: true,
        submissionId: submission.id,
        taskId: newTask.id,
        taskUrl: `/tasks/${newTask.id}`,
      });

    } catch (error: any) {
      const errorMessage = error?.message || String(error);
      const errorDetail = error?.detail || '';
      const errorCode = error?.code || '';
      console.error("[TaskIntake] Error submitting form:", {
        message: errorMessage,
        detail: errorDetail,
        code: errorCode,
        parentTaskId: req.body?.parentTaskId,
        formId: req.body?.formId,
        stack: error?.stack?.split('\n').slice(0, 5).join('\n'),
      });
      
      let userMessage = "Failed to submit form";
      if (errorCode === '23503') {
        userMessage = "A referenced record (client, project, category, or assignee) no longer exists. Please refresh and try again.";
      } else if (errorCode === '23505') {
        userMessage = "A duplicate record was detected. Please try again.";
      } else if (errorMessage.includes('null value in column')) {
        userMessage = "A required field is missing. Please fill out all required fields.";
      }
      
      res.status(500).json({ error: userMessage, message: userMessage, details: errorDetail || errorMessage });
    }
  });

  // GET /api/task-intake/submissions/:submissionId - Get submission with answers grouped by section
  app.get("/api/task-intake/submissions/:submissionId", requireAuth(), async (req, res) => {
    try {
      const { submissionId } = req.params;

      // Get the submission
      const [submission] = await db.select({
        id: taskIntakeSubmissions.id,
        taskId: taskIntakeSubmissions.taskId,
        formId: taskIntakeSubmissions.formId,
        submittedBy: taskIntakeSubmissions.submittedBy,
        submittedAt: taskIntakeSubmissions.submittedAt,
        status: taskIntakeSubmissions.status,
      })
        .from(taskIntakeSubmissions)
        .where(eq(taskIntakeSubmissions.id, submissionId));

      if (!submission) {
        return res.status(404).json({ error: "Submission not found" });
      }

      // Get submitter info
      const [submitter] = await db.select({
        id: staff.id,
        name: sql<string>`COALESCE(${staff.firstName} || ' ' || ${staff.lastName}, ${staff.email})`,
      })
        .from(staff)
        .where(eq(staff.id, submission.submittedBy));

      // Get all answers for this submission
      const answersData = await db.select({
        answerId: taskIntakeAnswers.id,
        questionId: taskIntakeAnswers.questionId,
        sectionId: taskIntakeAnswers.sectionId,
        answerValue: taskIntakeAnswers.answerValue,
        wasVisible: taskIntakeAnswers.wasVisible,
        questionText: taskIntakeQuestions.questionText,
        questionType: taskIntakeQuestions.questionType,
        internalLabel: taskIntakeQuestions.internalLabel,
        questionOrder: taskIntakeQuestions.order,
      })
        .from(taskIntakeAnswers)
        .innerJoin(taskIntakeQuestions, eq(taskIntakeAnswers.questionId, taskIntakeQuestions.id))
        .where(eq(taskIntakeAnswers.submissionId, submissionId))
        .orderBy(asc(taskIntakeQuestions.order));

      // Get sections for grouping
      const sections = await db.select({
        id: taskIntakeSections.id,
        sectionName: taskIntakeSections.sectionName,
        orderIndex: taskIntakeSections.orderIndex,
      })
        .from(taskIntakeSections)
        .where(eq(taskIntakeSections.formId, submission.formId))
        .orderBy(asc(taskIntakeSections.orderIndex));

      // Group answers by section
      const sectionMap = new Map<string, {
        sectionId: string;
        sectionName: string;
        wasVisible: boolean;
        answers: Array<{
          questionId: string;
          questionText: string;
          internalLabel: string | null;
          answerValue: string | null;
          questionType: string;
        }>;
      }>();

      // Initialize sections
      for (const section of sections) {
        sectionMap.set(section.id, {
          sectionId: section.id,
          sectionName: section.sectionName,
          wasVisible: false, // Will be set based on answers
          answers: [],
        });
      }

      // Populate answers
      for (const answer of answersData) {
        if (answer.sectionId) {
          const section = sectionMap.get(answer.sectionId);
          if (section) {
            if (answer.wasVisible) {
              section.wasVisible = true;
            }
            section.answers.push({
              questionId: answer.questionId,
              questionText: answer.questionText,
              internalLabel: answer.internalLabel,
              answerValue: answer.answerValue,
              questionType: answer.questionType,
            });
          }
        }
      }

      // Convert to array and filter to only sections with answers
      const sectionsWithAnswers = Array.from(sectionMap.values())
        .filter(s => s.answers.length > 0);

      res.json({
        id: submission.id,
        taskId: submission.taskId,
        submittedBy: submitter || { id: submission.submittedBy, name: 'Unknown User' },
        submittedAt: submission.submittedAt,
        status: submission.status,
        sections: sectionsWithAnswers,
      });

    } catch (error) {
      console.error("Error fetching submission:", error);
      res.status(500).json({ error: "Failed to fetch submission" });
    }
  });

  // GET /api/tasks/:taskId/intake-submission - Get submission by task ID
  app.get("/api/tasks/:taskId/intake-submission", requireAuth(), async (req, res) => {
    try {
      const { taskId } = req.params;

      // Find submission by taskId
      const [submission] = await db.select({
        id: taskIntakeSubmissions.id,
      })
        .from(taskIntakeSubmissions)
        .where(eq(taskIntakeSubmissions.taskId, taskId));

      if (!submission) {
        return res.status(404).json({ error: "No intake submission found for this task" });
      }

      // Redirect to the main submission endpoint logic
      // Reuse the same logic by making an internal call
      const submissionId = submission.id;

      // Get the full submission data
      const [fullSubmission] = await db.select({
        id: taskIntakeSubmissions.id,
        taskId: taskIntakeSubmissions.taskId,
        formId: taskIntakeSubmissions.formId,
        submittedBy: taskIntakeSubmissions.submittedBy,
        submittedAt: taskIntakeSubmissions.submittedAt,
        status: taskIntakeSubmissions.status,
      })
        .from(taskIntakeSubmissions)
        .where(eq(taskIntakeSubmissions.id, submissionId));

      // Get submitter info
      const [submitter] = await db.select({
        id: staff.id,
        name: sql<string>`COALESCE(${staff.firstName} || ' ' || ${staff.lastName}, ${staff.email})`,
      })
        .from(staff)
        .where(eq(staff.id, fullSubmission.submittedBy));

      // Get all answers
      const answersData = await db.select({
        answerId: taskIntakeAnswers.id,
        questionId: taskIntakeAnswers.questionId,
        sectionId: taskIntakeAnswers.sectionId,
        answerValue: taskIntakeAnswers.answerValue,
        wasVisible: taskIntakeAnswers.wasVisible,
        questionText: taskIntakeQuestions.questionText,
        questionType: taskIntakeQuestions.questionType,
        internalLabel: taskIntakeQuestions.internalLabel,
        questionOrder: taskIntakeQuestions.order,
      })
        .from(taskIntakeAnswers)
        .innerJoin(taskIntakeQuestions, eq(taskIntakeAnswers.questionId, taskIntakeQuestions.id))
        .where(eq(taskIntakeAnswers.submissionId, submissionId))
        .orderBy(asc(taskIntakeQuestions.order));

      // Get sections
      const sections = await db.select({
        id: taskIntakeSections.id,
        sectionName: taskIntakeSections.sectionName,
        orderIndex: taskIntakeSections.orderIndex,
      })
        .from(taskIntakeSections)
        .where(eq(taskIntakeSections.formId, fullSubmission.formId))
        .orderBy(asc(taskIntakeSections.orderIndex));

      // Group by section
      const sectionMap = new Map<string, {
        sectionId: string;
        sectionName: string;
        wasVisible: boolean;
        answers: Array<{
          questionId: string;
          questionText: string;
          internalLabel: string | null;
          answerValue: string | null;
          questionType: string;
        }>;
      }>();

      for (const section of sections) {
        sectionMap.set(section.id, {
          sectionId: section.id,
          sectionName: section.sectionName,
          wasVisible: false,
          answers: [],
        });
      }

      for (const answer of answersData) {
        if (answer.sectionId) {
          const section = sectionMap.get(answer.sectionId);
          if (section) {
            if (answer.wasVisible) {
              section.wasVisible = true;
            }
            section.answers.push({
              questionId: answer.questionId,
              questionText: answer.questionText,
              internalLabel: answer.internalLabel,
              answerValue: answer.answerValue,
              questionType: answer.questionType,
            });
          }
        }
      }

      const sectionsWithAnswers = Array.from(sectionMap.values())
        .filter(s => s.answers.length > 0);

      for (const section of sectionsWithAnswers) {
        for (const answer of section.answers) {
          if ((answer.internalLabel === "client_select" || answer.questionType === "client") && answer.answerValue) {
            if (answer.answerValue === "no_client") {
              answer.answerValue = "No client (internal task)";
            } else {
              try {
                const [client] = await db.select({ name: clients.name, company: clients.company })
                  .from(clients)
                  .where(eq(clients.id, answer.answerValue));
                if (client) {
                  answer.answerValue = client.company || client.name;
                }
              } catch {}
            }
          }
        }
      }

      res.json({
        id: fullSubmission.id,
        taskId: fullSubmission.taskId,
        submittedBy: submitter || { id: fullSubmission.submittedBy, name: 'Unknown User' },
        submittedAt: fullSubmission.submittedAt,
        status: fullSubmission.status,
        sections: sectionsWithAnswers,
      });

    } catch (error) {
      console.error("Error fetching task intake submission:", error);
      res.status(500).json({ error: "Failed to fetch intake submission" });
    }
  });

  // Team Workflows - Manage team-specific status workflows
  app.get("/api/team-workflows", requireAuth(), requirePermission('workflows', 'canView'), async (req, res) => {
    try {
      const workflows = await db.select()
        .from(teamWorkflows)
        .orderBy(asc(teamWorkflows.name));
      
      // Get statuses for each workflow using the same logic as the individual endpoint
      const workflowsWithStatuses = [];
      for (const workflow of workflows) {
        const workflowStatuses = await db
          .select({
            id: teamWorkflowStatuses.id,
            workflowId: teamWorkflowStatuses.workflowId,
            order: teamWorkflowStatuses.order,
            isRequired: teamWorkflowStatuses.isRequired,
            status: {
              id: taskStatuses.id,
              name: taskStatuses.name,
              value: taskStatuses.value,
              color: taskStatuses.color,
              isDefault: taskStatuses.isDefault,
            }
          })
          .from(teamWorkflowStatuses)
          .innerJoin(taskStatuses, eq(teamWorkflowStatuses.statusId, taskStatuses.id))
          .where(eq(teamWorkflowStatuses.workflowId, workflow.id))
          .orderBy(asc(teamWorkflowStatuses.order));

        workflowsWithStatuses.push({ ...workflow, statuses: workflowStatuses });
      }
      
      res.json(workflowsWithStatuses);
    } catch (error) {
      console.error("Error fetching team workflows:", error);
      res.status(500).json({ message: "Failed to fetch team workflows" });
    }
  });

