  // Update job application status and rating
  app.patch('/api/hr/job-applications/:id', requireAuth(), async (req, res) => {
    try {
      const { id } = req.params;
      const { stage, rating } = req.body;

      const [existingApp] = await db
        .select({ stage: jobApplications.stage })
        .from(jobApplications)
        .where(eq(jobApplications.id, id))
        .limit(1);

      if (!existingApp) {
        return res.status(404).json({ message: "Application not found" });
      }
      
      const updateData: any = {};
      if (stage !== undefined) updateData.stage = stage;
      if (rating !== undefined) updateData.rating = rating;
      updateData.lastUpdated = new Date();
      
      const [updatedApplication] = await db
        .update(jobApplications)
        .set(updateData)
        .where(eq(jobApplications.id, id))
        .returning();
      
      if (!updatedApplication) {
        return res.status(404).json({ message: "Application not found" });
      }

      if (stage === "hired" && existingApp.stage !== "hired") {
        const userId = getAuthenticatedUserId(req);
        const changedBy = userId || "system";

        try {
          const [offer] = await db
            .select()
            .from(jobOffers)
            .where(eq(jobOffers.applicationId, id))
            .limit(1);

          if (offer) {
            await db.insert(offerStatusLog).values({
              offerId: offer.id,
              status: "hired",
              changedBy: userId || null,
              note: "Applicant marked as hired",
            });
          }
        } catch (logErr) {
          console.error("[HiredStatus] Error logging offer status:", logErr);
        }

        // Welcome emails are now handled exclusively by the "Applicant Hired" workflow trigger.
        // sendHiredNotifications fires the trigger and notifies the manager in-app.
        sendHiredNotifications(id, changedBy).catch((err) =>
          console.error("Hired notification error:", err)
        );
      }

      // Mask salary expectation in response for users without HR application management permission
      const userIdForPerm = req.session?.userId;
      const canManageApplications = userIdForPerm
        ? await hasGranularPermission(userIdForPerm, 'hr.applications.manage')
        : false;
      const responseData: any = { ...updatedApplication };
      if (!canManageApplications && updatedApplication.salaryExpectation != null && updatedApplication.salaryExpectation !== '') {
        responseData.salaryExpectation = null;
        responseData.salaryHidden = true;
      }

      res.json(responseData);
    } catch (error) {
      console.error("Error updating job application:", error);
      res.status(500).json({ message: "Failed to update application" });
    }
  });

  // Delete a job application (admin only)
  app.delete('/api/hr/job-applications/:id', requireAuth(), async (req, res) => {
    try {
      const userId = getAuthenticatedUserIdOrFail(req, res);
      if (!userId) return;

      // Check if user is admin
      const [user] = await db.select({
        role: roles.name
      })
      .from(staff)
      .leftJoin(roles, eq(staff.roleId, roles.id))
      .where(eq(staff.id, userId));

      if (!user || user.role !== 'Admin') {
        return res.status(403).json({ message: "Only admins can delete job applications" });
      }

      const { id } = req.params;

      // Delete related comments first
      await db.delete(jobApplicationComments).where(eq(jobApplicationComments.applicationId, id));

      // Delete related watchers
      await db.delete(jobApplicationWatchers).where(eq(jobApplicationWatchers.applicationId, id));

      // Delete the application
      const [deletedApplication] = await db
        .delete(jobApplications)
        .where(eq(jobApplications.id, id))
        .returning();

      if (!deletedApplication) {
        return res.status(404).json({ message: "Application not found" });
      }

      res.json({ message: "Application deleted successfully" });
    } catch (error) {
      console.error("Error deleting job application:", error);
      res.status(500).json({ message: "Failed to delete application" });
    }
  });

