      // Get quiz questions
      const questions = await db.select().from(trainingQuizQuestions)
        .where(eq(trainingQuizQuestions.quizId, quiz.id))
        .orderBy(asc(trainingQuizQuestions.order));
      
      res.json({ ...quiz, questions });
