  // Manual add time entry for call center
  app.post("/api/call-center/manual-entry", requireAuth(), async (req, res) => {
    try {
      const currentUserId = getAuthenticatedUserIdOrFail(req, res);
      if (!currentUserId) return;

      const isAdmin = await isCurrentUserAdmin(req);
      let hasAccess = isAdmin;

      if (!hasAccess) {
        const roleIds: string[] = [];
        const staffRec = await db.select({ roleId: staff.roleId }).from(staff).where(eq(staff.id, currentUserId)).limit(1);
        if (staffRec.length > 0 && staffRec[0].roleId) roleIds.push(staffRec[0].roleId);
        const userRolesList = await db.select({ roleId: userRoles.roleId }).from(userRoles).where(eq(userRoles.userId, currentUserId));
        for (const ur of userRolesList) { if (ur.roleId && !roleIds.includes(ur.roleId)) roleIds.push(ur.roleId); }

        if (roleIds.length > 0) {
          const perms = await db
            .select({ permissionKey: granularPermissions.permissionKey })
            .from(granularPermissions)
            .where(
              and(
                inArray(granularPermissions.roleId, roleIds),
                eq(granularPermissions.permissionKey, 'call_center.time_tracking.add_time'),
                eq(granularPermissions.enabled, true)
              )
            );
          hasAccess = perms.length > 0;
        }
      }

      if (!hasAccess) {
        return res.status(403).json({ error: "You don't have permission to add call center time entries" });
      }

      const { userId, clientId, startTime, endTime } = req.body;
      if (!userId || !clientId || !startTime || !endTime) {
        return res.status(400).json({ error: "userId, clientId, startTime, and endTime are required" });
      }

      const start = new Date(startTime);
      const end = new Date(endTime);
      if (end <= start) {
        return res.status(400).json({ error: "End time must be after start time" });
      }

      const durationMinutes = Math.round((end.getTime() - start.getTime()) / 60000);

      const [entry] = await db
        .insert(callCenterTimeEntries)
        .values({
          userId,
          clientId,
          startTime: start,
          endTime: end,
          duration: durationMinutes,
          isRunning: false,
        })
        .returning();

      res.json(entry);
    } catch (error: any) {
      console.error("Error creating manual call center time entry:", error);
      res.status(500).json({ error: "Failed to create time entry" });
    }
  });

  // Edit call center time entry
  app.patch("/api/call-center/time-entry/:id", requireAuth(), async (req, res) => {
    try {
      const currentUserId = getAuthenticatedUserIdOrFail(req, res);
      if (!currentUserId) return;

      const isAdmin = await isCurrentUserAdmin(req);
      let hasAccess = isAdmin;

      if (!hasAccess) {
        const roleIds: string[] = [];
        const staffRec = await db.select({ roleId: staff.roleId }).from(staff).where(eq(staff.id, currentUserId)).limit(1);
        if (staffRec.length > 0 && staffRec[0].roleId) roleIds.push(staffRec[0].roleId);
        const userRolesList = await db.select({ roleId: userRoles.roleId }).from(userRoles).where(eq(userRoles.userId, currentUserId));
        for (const ur of userRolesList) { if (ur.roleId && !roleIds.includes(ur.roleId)) roleIds.push(ur.roleId); }

        if (roleIds.length > 0) {
          const perms = await db
            .select({ permissionKey: granularPermissions.permissionKey })
            .from(granularPermissions)
            .where(
              and(
                inArray(granularPermissions.roleId, roleIds),
                eq(granularPermissions.permissionKey, 'call_center.time_tracking.edit_time'),
                eq(granularPermissions.enabled, true)
              )
            );
          hasAccess = perms.length > 0;
        }
      }

      if (!hasAccess) {
        return res.status(403).json({ error: "You don't have permission to edit call center time entries" });
      }

      const { id } = req.params;
      const { userId, clientId, startTime, endTime } = req.body;

      const existing = await db.select().from(callCenterTimeEntries).where(eq(callCenterTimeEntries.id, id)).limit(1);
      if (existing.length === 0) {
        return res.status(404).json({ error: "Time entry not found" });
      }

      const updates: any = { updatedAt: new Date() };
      if (userId) updates.userId = userId;
      if (clientId) updates.clientId = clientId;

      const newStart = startTime ? new Date(startTime) : existing[0].startTime;
      const newEnd = endTime ? new Date(endTime) : existing[0].endTime;

      if (newStart && newEnd) {
        if (newEnd <= newStart) {
          return res.status(400).json({ error: "End time must be after start time" });
        }
        updates.startTime = newStart;
        updates.endTime = newEnd;
        updates.duration = Math.round((newEnd.getTime() - newStart.getTime()) / 60000);
      }

      const [updated] = await db
        .update(callCenterTimeEntries)
        .set(updates)
        .where(eq(callCenterTimeEntries.id, id))
        .returning();

      res.json(updated);
    } catch (error: any) {
      console.error("Error updating call center time entry:", error);
      res.status(500).json({ error: "Failed to update time entry" });
    }
  });

