  // ═══════════════════════════════════════════════════════════
  // ONBOARDING — MANAGER DASHBOARD ROUTES
  // ═══════════════════════════════════════════════════════════

  app.get("/api/onboarding/instances", requireAuth(), async (req, res) => {
    try {
      const userId = getAuthenticatedUserId(req)!;
      const isAdmin = await isCurrentUserAdmin(req);

      const directReports = await db.select({ id: staff.id })
        .from(staff)
        .where(and(eq(staff.managerId, userId), eq(staff.isActive, true)));
      const isManagerUser = directReports.length > 0;

      if (!isAdmin && !isManagerUser) {
        return res.status(403).json({ error: "Admin or Manager access required" });
      }

      const statusFilter = (req.query.status as string) || "active";
      const teamIdFilter = req.query.teamId as string;
      const searchFilter = req.query.search as string;

      const conditions: any[] = [];
      if (statusFilter !== "all") {
        conditions.push(eq(onboardingInstances.status, statusFilter));
      }

      if (!isAdmin) {
        const reportIds = directReports.map(r => r.id);
        if (reportIds.length > 0) {
          conditions.push(inArray(onboardingInstances.staffId, reportIds));
        } else {
          return res.json([]);
        }
      }

      if (teamIdFilter && isAdmin) {
        const deptStaff = await db.select({ id: staff.id })
          .from(staff)
          .where(eq(staff.department, teamIdFilter));
        const deptIds = deptStaff.map(s => s.id);
        if (deptIds.length > 0) {
          conditions.push(inArray(onboardingInstances.staffId, deptIds));
        } else {
          return res.json([]);
        }
      }

      let instances = await db.select({
        instance: onboardingInstances,
        staffMember: {
          id: staff.id,
          firstName: staff.firstName,
          lastName: staff.lastName,
          email: staff.email,
          position: staff.position,
          department: staff.department,
          profileImagePath: staff.profileImagePath,
        },
      })
        .from(onboardingInstances)
        .innerJoin(staff, eq(onboardingInstances.staffId, staff.id))
        .where(conditions.length > 0 ? and(...conditions) : undefined)
        .orderBy(desc(onboardingInstances.createdAt));

      if (searchFilter) {
        const search = searchFilter.toLowerCase();
        instances = instances.filter(i =>
          `${i.staffMember.firstName} ${i.staffMember.lastName}`.toLowerCase().includes(search)
        );
      }

      const results = await Promise.all(instances.map(async ({ instance, staffMember }) => {
        const items = await db.select()
          .from(onboardingInstanceItems)
          .where(eq(onboardingInstanceItems.instanceId, instance.id));

        const snapshot = instance.templateSnapshot as any;
        const totalDays = snapshot?.totalDays || 1;
        const dayUnlockMode = snapshot?.dayUnlockMode || "calendar";

        const totalItems = items.length;
        const completedItems = items.filter(i => i.isCompleted).length;
        const requiredItems = items.filter(i => i.isRequired).length;
        const completedRequiredItems = items.filter(i => i.isRequired && i.isCompleted).length;

        const startDate = new Date(instance.startDate);
        const today = new Date();
        let daysDiff = 0;
        const d = new Date(startDate);
        while (d <= today) {
          const dow = d.getDay();
          if (dow !== 0 && dow !== 6) daysDiff++;
          d.setDate(d.getDate() + 1);
        }
        const currentDay = Math.max(1, Math.min(daysDiff, totalDays));

        const percentComplete = requiredItems > 0 ? Math.round((completedRequiredItems / requiredItems) * 100) : 100;
        const isBehind = items.some(i => i.isRequired && !i.isCompleted && i.dayNumber < currentDay);

        return {
          ...instance,
          totalDays,
          dayUnlockMode,
          staffMember,
          progress: {
            totalItems,
            completedItems,
            requiredItems,
            completedRequiredItems,
            currentDay,
            percentComplete,
            isBehind,
          },
        };
      }));

      res.json(results);
    } catch (error: any) {
      console.error("Error fetching onboarding instances:", error);
      res.status(500).json({ error: "Failed to fetch onboarding instances" });
    }
  });

  app.get("/api/onboarding/instances/:instanceId", requireAuth(), async (req, res) => {
    try {
      const userId = getAuthenticatedUserId(req)!;
      const isAdmin = await isCurrentUserAdmin(req);
      const instanceId = parseInt(req.params.instanceId);

      const [result] = await db.select({
        instance: onboardingInstances,
        staffMember: {
          id: staff.id,
          firstName: staff.firstName,
          lastName: staff.lastName,
          email: staff.email,
          position: staff.position,
          department: staff.department,
          profileImagePath: staff.profileImagePath,
        },
      })
        .from(onboardingInstances)
        .innerJoin(staff, eq(onboardingInstances.staffId, staff.id))
        .where(eq(onboardingInstances.id, instanceId));

      if (!result) {
        return res.status(404).json({ error: "Instance not found" });
      }

      if (!isAdmin) {
        const directReports = await db.select({ id: staff.id })
          .from(staff)
          .where(and(eq(staff.managerId, userId), eq(staff.isActive, true)));
        const reportIds = directReports.map(r => r.id);
        if (!reportIds.includes(result.staffMember.id)) {
          return res.status(403).json({ error: "You can only view instances for your team members" });
        }
      }

      const { instance, staffMember } = result;
      const snapshot = instance.templateSnapshot as any;
      const totalDays = snapshot?.totalDays || 1;
      const dayUnlockMode = snapshot?.dayUnlockMode || "calendar";

      const items = await db.select()
        .from(onboardingInstanceItems)
        .where(eq(onboardingInstanceItems.instanceId, instance.id))
        .orderBy(onboardingInstanceItems.dayNumber, onboardingInstanceItems.sortOrder);

      const enrichedItems = await Promise.all(items.map(async (item) => {
        let referenceTitle: string | null = null;
        let referenceUrl: string | null = null;
        if (item.itemType === "kb_article" && item.referenceId) {
          const [article] = await db.select({ title: knowledgeBaseArticles.title, slug: knowledgeBaseArticles.slug })
            .from(knowledgeBaseArticles)
            .where(eq(knowledgeBaseArticles.id, String(item.referenceId)));
          if (article) {
            referenceTitle = article.title;
            referenceUrl = `/resources/articles/${item.referenceId}`;
          }
        } else if (item.itemType === "training_course" && item.referenceId) {
          const [course] = await db.select({ title: trainingCourses.title })
            .from(trainingCourses)
            .where(eq(trainingCourses.id, String(item.referenceId)));
          if (course) {
            referenceTitle = course.title;
            referenceUrl = `/training/courses/${item.referenceId}`;
          }
        }
        return { ...item, referenceTitle, referenceUrl };
      }));

      const totalItems = items.length;
      const completedItems = items.filter(i => i.isCompleted).length;
      const requiredItems = items.filter(i => i.isRequired).length;
      const completedRequiredItems = items.filter(i => i.isRequired && i.isCompleted).length;

      const startDate = new Date(instance.startDate);
      const today = new Date();
      let daysDiff = 0;
      const d = new Date(startDate);
      while (d <= today) {
        const dow = d.getDay();
        if (dow !== 0 && dow !== 6) daysDiff++;
        d.setDate(d.getDate() + 1);
      }
      const currentDay = Math.max(1, Math.min(daysDiff, totalDays));
      const percentComplete = requiredItems > 0 ? Math.round((completedRequiredItems / requiredItems) * 100) : 100;
      const isBehind = items.some(i => i.isRequired && !i.isCompleted && i.dayNumber < currentDay);

      res.json({
        ...instance,
        totalDays,
        dayUnlockMode,
        staffMember,
        progress: {
          totalItems,
          completedItems,
          requiredItems,
          completedRequiredItems,
          currentDay,
          percentComplete,
          isBehind,
        },
        items: enrichedItems,
      });
    } catch (error: any) {
      console.error("Error fetching onboarding instance detail:", error);
      res.status(500).json({ error: "Failed to fetch onboarding instance" });
    }
  });

  app.patch("/api/onboarding/instances/:instanceId/items/:itemId", requireAuth(), async (req, res) => {
    try {
      const userId = getAuthenticatedUserId(req)!;
      const isAdmin = await isCurrentUserAdmin(req);
      const instanceId = parseInt(req.params.instanceId);
      const itemId = parseInt(req.params.itemId);
      const { isCompleted } = req.body;

      if (typeof isCompleted !== "boolean") {
        return res.status(400).json({ error: "isCompleted must be a boolean" });
      }

      if (!isAdmin) {
        const directReports = await db.select({ id: staff.id })
          .from(staff)
          .where(and(eq(staff.managerId, userId), eq(staff.isActive, true)));
        const [inst] = await db.select({ staffId: onboardingInstances.staffId })
          .from(onboardingInstances)
          .where(eq(onboardingInstances.id, instanceId));
        if (!inst || !directReports.some(r => r.id === inst.staffId)) {
          return res.status(403).json({ error: "You can only modify items for your team members" });
        }
      }

      const [item] = await db.select()
        .from(onboardingInstanceItems)
        .where(and(eq(onboardingInstanceItems.id, itemId), eq(onboardingInstanceItems.instanceId, instanceId)));

      if (!item) {
        return res.status(404).json({ error: "Item not found" });
      }

      const updateData = isCompleted
        ? { isCompleted: true, completedAt: new Date(), completedBy: userId, autoCompleted: false }
        : { isCompleted: false, completedAt: null, completedBy: null, autoCompleted: false };

      const [updated] = await db.update(onboardingInstanceItems)
        .set(updateData)
        .where(eq(onboardingInstanceItems.id, itemId))
        .returning();

      if (isCompleted) {
        const allRequiredItems = await db.select()
          .from(onboardingInstanceItems)
          .where(and(
            eq(onboardingInstanceItems.instanceId, instanceId),
            eq(onboardingInstanceItems.isRequired, true)
          ));
        const allComplete = allRequiredItems.every(i => i.id === itemId ? true : i.isCompleted);
        if (allComplete) {
          await db.update(onboardingInstances)
            .set({ status: "completed", completedAt: new Date() })
            .where(eq(onboardingInstances.id, instanceId));
        }
      } else {
        const [inst] = await db.select()
          .from(onboardingInstances)
          .where(eq(onboardingInstances.id, instanceId));
        if (inst?.status === "completed") {
          await db.update(onboardingInstances)
            .set({ status: "active", completedAt: null })
            .where(eq(onboardingInstances.id, instanceId));
        }
      }

      res.json(updated);
    } catch (error: any) {
      console.error("Error updating onboarding item:", error);
      res.status(500).json({ error: "Failed to update onboarding item" });
    }
  });

  app.patch("/api/onboarding/instances/:instanceId/status", requireAuth(), async (req, res) => {
    try {
      const userId = getAuthenticatedUserId(req)!;
      const isAdmin = await isCurrentUserAdmin(req);
      const instanceId = parseInt(req.params.instanceId);
      const { status: newStatus } = req.body;

      if (!["active", "paused", "completed"].includes(newStatus)) {
        return res.status(400).json({ error: "Status must be active, paused, or completed" });
      }

      if (!isAdmin) {
        const directReports = await db.select({ id: staff.id })
          .from(staff)
          .where(and(eq(staff.managerId, userId), eq(staff.isActive, true)));
        const [inst] = await db.select({ staffId: onboardingInstances.staffId })
          .from(onboardingInstances)
          .where(eq(onboardingInstances.id, instanceId));
        if (!inst || !directReports.some(r => r.id === inst.staffId)) {
          return res.status(403).json({ error: "You can only modify instances for your team members" });
        }
      }

      const updateData: any = { status: newStatus };
      if (newStatus === "completed") {
        updateData.completedAt = new Date();
      } else {
        updateData.completedAt = null;
      }

      const [updated] = await db.update(onboardingInstances)
        .set(updateData)
        .where(eq(onboardingInstances.id, instanceId))
        .returning();

      if (!updated) {
        return res.status(404).json({ error: "Instance not found" });
      }

      res.json(updated);
    } catch (error: any) {
      console.error("Error updating onboarding instance status:", error);
      res.status(500).json({ error: "Failed to update instance status" });
    }
  });

  // ═══════════════════════════════════════════════════════════
  // ONBOARDING — STAFF ONBOARDING HISTORY
  // ═══════════════════════════════════════════════════════════

  app.get("/api/staff/:staffId/onboarding-history", requireAuth(), async (req, res) => {
    try {
      const isAdmin = await isCurrentUserAdmin(req);
      if (!isAdmin) {
        return res.status(403).json({ error: "Admin or Manager access required" });
      }

      const { staffId } = req.params;

      const instances = await db.select()
        .from(onboardingInstances)
        .where(eq(onboardingInstances.staffId, staffId))
        .orderBy(sql`${onboardingInstances.createdAt} DESC`);

      const result = [];
      for (const inst of instances) {
        const items = await db.select()
          .from(onboardingInstanceItems)
          .where(eq(onboardingInstanceItems.instanceId, inst.id));

        const totalItems = items.length;
        const completedItems = items.filter(i => i.isCompleted).length;
        const requiredItems = items.filter(i => i.isRequired).length;
        const completedRequiredItems = items.filter(i => i.isRequired && i.isCompleted).length;
        const percentComplete = totalItems > 0 ? Math.round((completedItems / totalItems) * 100) : 0;

        const snapshot = inst.templateSnapshot as any;

        result.push({
          id: inst.id,
          status: inst.status,
          startDate: inst.startDate,
          completedAt: inst.completedAt,
          createdAt: inst.createdAt,
          totalDays: snapshot?.totalDays || 0,
          positionName: snapshot?.positionName || "Unknown",
          totalItems,
          completedItems,
          requiredItems,
          completedRequiredItems,
          percentComplete,
        });
      }

      res.json(result);
    } catch (error: any) {
      console.error("Error fetching onboarding history:", error);
      res.status(500).json({ error: "Failed to fetch onboarding history" });
    }
  });

  app.get("/api/staff/:staffId/onboarding-history/:instanceId", requireAuth(), async (req, res) => {
    try {
      const isAdmin = await isCurrentUserAdmin(req);
      if (!isAdmin) {
        return res.status(403).json({ error: "Admin or Manager access required" });
      }

      const instanceId = parseInt(req.params.instanceId);
      const { staffId } = req.params;

      const [instance] = await db.select()
        .from(onboardingInstances)
        .where(and(
          eq(onboardingInstances.id, instanceId),
          eq(onboardingInstances.staffId, staffId)
        ));

      if (!instance) {
        return res.status(404).json({ error: "Instance not found" });
      }

      const items = await db.select()
        .from(onboardingInstanceItems)
        .where(eq(onboardingInstanceItems.instanceId, instanceId))
        .orderBy(onboardingInstanceItems.dayNumber, onboardingInstanceItems.orderIndex);

      const snapshot = instance.templateSnapshot as any;

      const completedByIds = [...new Set(items.filter(i => i.completedBy).map(i => i.completedBy!))];
      let completedByMap: Record<string, string> = {};
      if (completedByIds.length > 0) {
        const staffMembers = await db.select({ id: staff.id, firstName: staff.firstName, lastName: staff.lastName })
          .from(staff)
          .where(sql`${staff.id} IN ${completedByIds}`);
        for (const s of staffMembers) {
          completedByMap[s.id] = `${s.firstName} ${s.lastName}`;
        }
      }

      const dayMap: Record<number, any[]> = {};
      for (const item of items) {
        const dn = item.dayNumber;
        if (!dayMap[dn]) dayMap[dn] = [];
        dayMap[dn].push({
          ...item,
          completedByName: item.completedBy ? completedByMap[item.completedBy] || null : null,
        });
      }

      const days = Object.entries(dayMap).map(([dayNum, dayItems]) => ({
        dayNumber: parseInt(dayNum),
        items: dayItems,
      })).sort((a, b) => a.dayNumber - b.dayNumber);

      const totalItems = items.length;
      const completedItems = items.filter(i => i.isCompleted).length;
      const requiredItems = items.filter(i => i.isRequired).length;
      const completedRequiredItems = items.filter(i => i.isRequired && i.isCompleted).length;

      res.json({
        ...instance,
        positionName: snapshot?.positionName || "Unknown",
        totalDays: snapshot?.totalDays || 0,
        dayUnlockMode: snapshot?.dayUnlockMode || "calendar",
        totalItems,
        completedItems,
        requiredItems,
        completedRequiredItems,
        percentComplete: totalItems > 0 ? Math.round((completedItems / totalItems) * 100) : 0,
        days,
      });
    } catch (error: any) {
      console.error("Error fetching onboarding history detail:", error);
      res.status(500).json({ error: "Failed to fetch onboarding history detail" });
    }
  });

  // ═══════════════════════════════════════════════════════════
  // ONBOARDING — LMS SYNC (ADMIN MANUAL TRIGGER)
  // ═══════════════════════════════════════════════════════════

  app.post("/api/onboarding/instances/:instanceId/sync-lms", requireAuth(), async (req, res) => {
    try {
      const isAdmin = await isCurrentUserAdmin(req);
      if (!isAdmin) {
        return res.status(403).json({ error: "Admin access required" });
      }

      const instanceId = parseInt(req.params.instanceId);
      const [instance] = await db.select()
        .from(onboardingInstances)
        .where(eq(onboardingInstances.id, instanceId));

      if (!instance) {
        return res.status(404).json({ error: "Instance not found" });
      }

      const incompleteTrainingItems = await db.select()
        .from(onboardingInstanceItems)
        .where(and(
          eq(onboardingInstanceItems.instanceId, instanceId),
          eq(onboardingInstanceItems.itemType, "training_course"),
          sql`${onboardingInstanceItems.referenceId} IS NOT NULL`,
          eq(onboardingInstanceItems.isCompleted, false)
        ));

      let synced = 0;
      for (const item of incompleteTrainingItems) {
        const courseId = String(item.referenceId);
        const [completion] = await db.select({ id: trainingEnrollments.id })
          .from(trainingEnrollments)
          .where(and(
            eq(trainingEnrollments.courseId, courseId),
            eq(trainingEnrollments.userId, instance.staffId),
            eq(trainingEnrollments.status, "completed")
          ));

        if (completion) {
          await syncLmsCompletion(instance.staffId, courseId);
          synced++;
        }
      }

      res.json({
        synced,
        message: synced > 0 ? `Synced ${synced} training completion(s)` : "No new completions to sync",
      });
    } catch (error: any) {
      console.error("Error syncing LMS completions:", error);
      res.status(500).json({ error: "Failed to sync LMS completions" });
    }
  });

  // ═══════════════════════════════════════════════════════════
  // ONBOARDING — NEW HIRE CHECKLIST ROUTES
  // ═══════════════════════════════════════════════════════════

  app.get("/api/onboarding/my-checklist", requireAuth(), async (req, res) => {
    try {
      const userId = getAuthenticatedUserId(req)!;

      const [instance] = await db.select()
        .from(onboardingInstances)
        .where(and(
          eq(onboardingInstances.staffId, userId),
          eq(onboardingInstances.status, "active")
        ))
        .limit(1);

      if (!instance) {
        const [completedInstance] = await db.select()
          .from(onboardingInstances)
          .where(and(
            eq(onboardingInstances.staffId, userId),
            eq(onboardingInstances.status, "completed")
          ))
          .orderBy(desc(onboardingInstances.completedAt))
          .limit(1);

        if (!completedInstance) {
          return res.json({ instance: null, items: [] });
        }

        const snapshot = completedInstance.templateSnapshot as any;
        const items = await db.select()
          .from(onboardingInstanceItems)
          .where(eq(onboardingInstanceItems.instanceId, completedInstance.id))
          .orderBy(onboardingInstanceItems.dayNumber, onboardingInstanceItems.sortOrder);

        const enrichedItems = await Promise.all(items.map(async (item) => {
          let referenceTitle: string | null = null;
          let referenceUrl: string | null = null;
          if (item.itemType === "kb_article" && item.referenceId) {
            const [article] = await db.select({ title: knowledgeBaseArticles.title, slug: knowledgeBaseArticles.slug })
              .from(knowledgeBaseArticles)
              .where(eq(knowledgeBaseArticles.id, String(item.referenceId)));
            if (article) {
              referenceTitle = article.title;
              referenceUrl = `/resources/articles/${item.referenceId}`;
            }
          } else if (item.itemType === "training_course" && item.referenceId) {
            const [course] = await db.select({ title: trainingCourses.title })
              .from(trainingCourses)
              .where(eq(trainingCourses.id, String(item.referenceId)));
            if (course) {
              referenceTitle = course.title;
              referenceUrl = `/training/courses/${item.referenceId}`;
            }
          }
          return { ...item, referenceTitle, referenceUrl };
        }));

        return res.json({
          instance: {
            ...completedInstance,
            totalDays: snapshot?.totalDays || 1,
            dayUnlockMode: snapshot?.dayUnlockMode || "calendar",
          },
          items: enrichedItems,
        });
      }

      const snapshot = instance.templateSnapshot as any;
      const items = await db.select()
        .from(onboardingInstanceItems)
        .where(eq(onboardingInstanceItems.instanceId, instance.id))
        .orderBy(onboardingInstanceItems.dayNumber, onboardingInstanceItems.sortOrder);

      const enrichedItems = await Promise.all(items.map(async (item) => {
        let referenceTitle: string | null = null;
        let referenceUrl: string | null = null;
        if (item.itemType === "kb_article" && item.referenceId) {
          const [article] = await db.select({ title: knowledgeBaseArticles.title, slug: knowledgeBaseArticles.slug })
            .from(knowledgeBaseArticles)
            .where(eq(knowledgeBaseArticles.id, String(item.referenceId)));
          if (article) {
            referenceTitle = article.title;
            referenceUrl = `/resources/articles/${item.referenceId}`;
          }
        } else if (item.itemType === "training_course" && item.referenceId) {
          const [course] = await db.select({ title: trainingCourses.title })
            .from(trainingCourses)
            .where(eq(trainingCourses.id, String(item.referenceId)));
          if (course) {
            referenceTitle = course.title;
            referenceUrl = `/training/courses/${item.referenceId}`;
          }
        }
        return { ...item, referenceTitle, referenceUrl };
      }));

      res.json({
        instance: {
          ...instance,
          totalDays: snapshot?.totalDays || 1,
          dayUnlockMode: snapshot?.dayUnlockMode || "calendar",
        },
        items: enrichedItems,
      });
    } catch (error: any) {
      console.error("Error fetching onboarding checklist:", error);
      res.status(500).json({ error: "Failed to fetch onboarding checklist" });
    }
  });

  app.patch("/api/onboarding/my-checklist/items/:itemId", requireAuth(), async (req, res) => {
    try {
      const userId = getAuthenticatedUserId(req)!;
      const itemId = parseInt(req.params.itemId);
      const { isCompleted } = req.body;

      if (typeof isCompleted !== "boolean") {
        return res.status(400).json({ error: "isCompleted must be a boolean" });
      }

      const [item] = await db.select()
        .from(onboardingInstanceItems)
        .where(eq(onboardingInstanceItems.id, itemId));

      if (!item) {
        return res.status(404).json({ error: "Item not found" });
      }

      const [instance] = await db.select()
        .from(onboardingInstances)
        .where(and(
          eq(onboardingInstances.id, item.instanceId),
          eq(onboardingInstances.staffId, userId),
          eq(onboardingInstances.status, "active")
        ));

      if (!instance) {
        return res.status(403).json({ error: "Item does not belong to your active onboarding checklist" });
      }

      const updateData = isCompleted
        ? { isCompleted: true, completedAt: new Date(), completedBy: userId, autoCompleted: false }
        : { isCompleted: false, completedAt: null, completedBy: null, autoCompleted: false };

      const [updated] = await db.update(onboardingInstanceItems)
        .set(updateData)
        .where(eq(onboardingInstanceItems.id, itemId))
        .returning();

      if (isCompleted) {
        const allRequiredItems = await db.select()
          .from(onboardingInstanceItems)
          .where(and(
            eq(onboardingInstanceItems.instanceId, instance.id),
            eq(onboardingInstanceItems.isRequired, true)
          ));

        const allComplete = allRequiredItems.every(i => i.id === itemId ? true : i.isCompleted);

        if (allComplete) {
          await db.update(onboardingInstances)
            .set({ status: "completed", completedAt: new Date() })
            .where(eq(onboardingInstances.id, instance.id));
        }
      } else {
        if (instance.status === "completed") {
          await db.update(onboardingInstances)
            .set({ status: "active", completedAt: null })
            .where(eq(onboardingInstances.id, instance.id));
        }
      }

      res.json(updated);
    } catch (error: any) {
      console.error("Error updating onboarding item:", error);
      res.status(500).json({ error: "Failed to update onboarding item" });
    }
  });

  app.get("/api/onboarding/my-checklist/progress", requireAuth(), async (req, res) => {
    try {
      const userId = getAuthenticatedUserId(req)!;

      const [instance] = await db.select()
        .from(onboardingInstances)
        .where(and(
          eq(onboardingInstances.staffId, userId),
          sql`${onboardingInstances.status} IN ('active', 'completed')`
        ))
        .orderBy(desc(onboardingInstances.createdAt))
        .limit(1);

      if (!instance) {
        return res.json({ totalItems: 0, completedItems: 0, requiredItems: 0, completedRequiredItems: 0, currentDay: 0, totalDays: 0, percentComplete: 0, isComplete: false });
      }

      const snapshot = instance.templateSnapshot as any;
      const totalDays = snapshot?.totalDays || 1;

      const items = await db.select()
        .from(onboardingInstanceItems)
        .where(eq(onboardingInstanceItems.instanceId, instance.id));

      const totalItems = items.length;
      const completedItems = items.filter(i => i.isCompleted).length;
      const requiredItems = items.filter(i => i.isRequired).length;
      const completedRequiredItems = items.filter(i => i.isRequired && i.isCompleted).length;

      const startDate = new Date(instance.startDate);
      const today = new Date();
      let daysDiff = 0;
      const d = new Date(startDate);
      while (d <= today) {
        const dow = d.getDay();
        if (dow !== 0 && dow !== 6) daysDiff++;
        d.setDate(d.getDate() + 1);
      }
      const currentDay = Math.max(1, Math.min(daysDiff, totalDays));

      const percentComplete = requiredItems > 0 ? Math.round((completedRequiredItems / requiredItems) * 100) : 100;

      res.json({
        totalItems,
        completedItems,
        requiredItems,
        completedRequiredItems,
        currentDay,
        totalDays,
        percentComplete,
        isComplete: instance.status === "completed",
      });
    } catch (error: any) {
      console.error("Error fetching onboarding progress:", error);
      res.status(500).json({ error: "Failed to fetch onboarding progress" });
    }
  });

  // ═══════════════════════════════════════════════════════════
  // ONBOARDING TEMPLATES API
  // ═══════════════════════════════════════════════════════════

  app.get("/api/onboarding-templates", requireAuth(), requirePermission('hr', 'canView'), async (req, res) => {
    try {
      const userId = getAuthenticatedUserId(req)!;
      const isAdmin = await isCurrentUserAdmin(req);

      const [currentUser] = await db.select({ department: staff.department }).from(staff).where(eq(staff.id, userId));

      let templates;
      if (isAdmin) {
        templates = await db.select({
          id: onboardingTemplates.id,
          teamId: onboardingTemplates.teamId,
          positionName: onboardingTemplates.positionName,
          totalDays: onboardingTemplates.totalDays,
          dayUnlockMode: onboardingTemplates.dayUnlockMode,
          createdBy: onboardingTemplates.createdBy,
          createdAt: onboardingTemplates.createdAt,
          updatedAt: onboardingTemplates.updatedAt,
          teamName: departments.name,
          itemCount: sql<number>`(SELECT COUNT(*) FROM onboarding_template_items WHERE template_id = ${onboardingTemplates.id})::int`,
        })
          .from(onboardingTemplates)
          .leftJoin(departments, eq(onboardingTemplates.teamId, departments.id))
          .orderBy(departments.name, onboardingTemplates.positionName);
      } else {
        const [dept] = currentUser?.department
          ? await db.select({ id: departments.id }).from(departments).where(eq(departments.name, currentUser.department))
          : [null];
        if (!dept) {
          return res.json([]);
        }
        templates = await db.select({
          id: onboardingTemplates.id,
          teamId: onboardingTemplates.teamId,
          positionName: onboardingTemplates.positionName,
          totalDays: onboardingTemplates.totalDays,
          dayUnlockMode: onboardingTemplates.dayUnlockMode,
          createdBy: onboardingTemplates.createdBy,
          createdAt: onboardingTemplates.createdAt,
          updatedAt: onboardingTemplates.updatedAt,
          teamName: departments.name,
          itemCount: sql<number>`(SELECT COUNT(*) FROM onboarding_template_items WHERE template_id = ${onboardingTemplates.id})::int`,
        })
          .from(onboardingTemplates)
          .leftJoin(departments, eq(onboardingTemplates.teamId, departments.id))
          .where(eq(onboardingTemplates.teamId, dept.id))
          .orderBy(onboardingTemplates.positionName);
      }
      res.json(templates);
    } catch (error: any) {
      console.error("Error fetching onboarding templates:", error);
      res.status(500).json({ error: "Failed to fetch onboarding templates" });
    }
  });

  app.get("/api/onboarding-templates/:id", requireAuth(), requirePermission('hr', 'canView'), async (req, res) => {
    try {
      const templateId = parseInt(req.params.id);
      const [template] = await db.select({
        id: onboardingTemplates.id,
        teamId: onboardingTemplates.teamId,
        positionName: onboardingTemplates.positionName,
        totalDays: onboardingTemplates.totalDays,
        dayUnlockMode: onboardingTemplates.dayUnlockMode,
        createdBy: onboardingTemplates.createdBy,
        createdAt: onboardingTemplates.createdAt,
        updatedAt: onboardingTemplates.updatedAt,
        teamName: departments.name,
      })
        .from(onboardingTemplates)
        .leftJoin(departments, eq(onboardingTemplates.teamId, departments.id))
        .where(eq(onboardingTemplates.id, templateId));

      if (!template) {
        return res.status(404).json({ error: "Template not found" });
      }

      const items = await db.select()
        .from(onboardingTemplateItems)
        .where(eq(onboardingTemplateItems.templateId, templateId))
        .orderBy(onboardingTemplateItems.dayNumber, onboardingTemplateItems.sortOrder);

      res.json({ ...template, items });
    } catch (error: any) {
      console.error("Error fetching onboarding template:", error);
      res.status(500).json({ error: "Failed to fetch onboarding template" });
    }
  });

  app.post("/api/onboarding-templates", requireAuth(), requirePermission('hr', 'canManage'), async (req, res) => {
    try {
      const userId = getAuthenticatedUserId(req)!;
      const isAdmin = await isCurrentUserAdmin(req);

      const parsed = insertOnboardingTemplateSchema.parse({
        ...req.body,
        createdBy: userId,
      });

      if (!isAdmin) {
        const [currentUser] = await db.select({ department: staff.department }).from(staff).where(eq(staff.id, userId));
        const [dept] = currentUser?.department
          ? await db.select({ id: departments.id }).from(departments).where(eq(departments.name, currentUser.department))
          : [null];
        if (!dept || dept.id !== parsed.teamId) {
          return res.status(403).json({ error: "You can only create templates for your own team" });
        }
      }

      const [template] = await db.insert(onboardingTemplates).values(parsed).returning();
      res.status(201).json(template);
    } catch (error: any) {
      console.error("Error creating onboarding template:", error);
      res.status(500).json({ error: "Failed to create onboarding template" });
    }
  });

  app.put("/api/onboarding-templates/:id", requireAuth(), requirePermission('hr', 'canManage'), async (req, res) => {
    try {
      const userId = getAuthenticatedUserId(req)!;
      const isAdmin = await isCurrentUserAdmin(req);
      const templateId = parseInt(req.params.id);

      const [existing] = await db.select().from(onboardingTemplates).where(eq(onboardingTemplates.id, templateId));
      if (!existing) {
        return res.status(404).json({ error: "Template not found" });
      }

      if (!isAdmin) {
        const [currentUser] = await db.select({ department: staff.department }).from(staff).where(eq(staff.id, userId));
        const [dept] = currentUser?.department
          ? await db.select({ id: departments.id }).from(departments).where(eq(departments.name, currentUser.department))
          : [null];
        if (!dept || dept.id !== existing.teamId) {
          return res.status(403).json({ error: "You can only edit templates for your own team" });
        }
      }

      const { positionName, totalDays, dayUnlockMode } = req.body;
      const [updated] = await db.update(onboardingTemplates)
        .set({
          ...(positionName !== undefined && { positionName }),
          ...(totalDays !== undefined && { totalDays }),
          ...(dayUnlockMode !== undefined && { dayUnlockMode }),
          updatedAt: new Date(),
        })
        .where(eq(onboardingTemplates.id, templateId))
        .returning();

      res.json(updated);
    } catch (error: any) {
      console.error("Error updating onboarding template:", error);
      res.status(500).json({ error: "Failed to update onboarding template" });
    }
  });

  app.delete("/api/onboarding-templates/:id", requireAuth(), requirePermission('hr', 'canManage'), async (req, res) => {
    try {
      const userId = getAuthenticatedUserId(req)!;
      const isAdmin = await isCurrentUserAdmin(req);
      const templateId = parseInt(req.params.id);

      if (!isAdmin) {
        const [existing] = await db.select({ teamId: onboardingTemplates.teamId }).from(onboardingTemplates).where(eq(onboardingTemplates.id, templateId));
        if (existing) {
          const [currentUser] = await db.select({ department: staff.department }).from(staff).where(eq(staff.id, userId));
          const [dept] = currentUser?.department
            ? await db.select({ id: departments.id }).from(departments).where(eq(departments.name, currentUser.department))
            : [null];
          if (!dept || dept.id !== existing.teamId) {
            return res.status(403).json({ error: "You can only delete templates for your own team" });
          }
        }
      }

      const [instance] = await db.select({ id: onboardingInstances.id })
        .from(onboardingInstances)
        .where(eq(onboardingInstances.templateId, templateId))
        .limit(1);

      if (instance) {
        return res.status(400).json({ error: "Cannot delete — active onboarding instances exist for this template." });
      }

      await db.delete(onboardingTemplates).where(eq(onboardingTemplates.id, templateId));
      res.json({ success: true });
    } catch (error: any) {
      console.error("Error deleting onboarding template:", error);
      res.status(500).json({ error: "Failed to delete onboarding template" });
    }
  });


  app.post("/api/onboarding-templates/:id/duplicate", requireAuth(), requirePermission('hr', 'canManage'), async (req, res) => {
    try {
      const userId = getAuthenticatedUserId(req)!;
      const templateId = parseInt(req.params.id);

      const [source] = await db.select().from(onboardingTemplates).where(eq(onboardingTemplates.id, templateId));
      if (!source) {
        return res.status(404).json({ error: "Template not found" });
      }

      const sourceItems = await db.select().from(onboardingTemplateItems).where(eq(onboardingTemplateItems.templateId, templateId)).orderBy(onboardingTemplateItems.dayNumber, onboardingTemplateItems.sortOrder);

      const newPositionName = `${source.positionName} (Copy)`;
      const [newTemplate] = await db.insert(onboardingTemplates).values({
        teamId: source.teamId,
        positionName: newPositionName,
        totalDays: source.totalDays,
        dayUnlockMode: source.dayUnlockMode,
        createdBy: userId,
      }).returning();

      if (sourceItems.length > 0) {
        await db.insert(onboardingTemplateItems).values(
          sourceItems.map(item => ({
            templateId: newTemplate.id,
            dayNumber: item.dayNumber,
            title: item.title,
            description: item.description,
            itemType: item.itemType,
            resourceUrl: item.resourceUrl,
            sortOrder: item.sortOrder,
          }))
        );
      }

      res.status(201).json(newTemplate);
    } catch (error: any) {
      console.error("Error duplicating onboarding template:", error);
      res.status(500).json({ error: "Failed to duplicate onboarding template" });
    }
  });

  app.post("/api/onboarding-templates/:id/items", requireAuth(), requirePermission('hr', 'canManage'), async (req, res) => {
    try {
      const userId = getAuthenticatedUserId(req)!;
      const isAdmin = await isCurrentUserAdmin(req);
      const templateId = parseInt(req.params.id);

      const [tmpl] = await db.select({ teamId: onboardingTemplates.teamId }).from(onboardingTemplates).where(eq(onboardingTemplates.id, templateId));
      if (!tmpl) return res.status(404).json({ error: "Template not found" });

      if (!isAdmin) {
        const [currentUser] = await db.select({ department: staff.department }).from(staff).where(eq(staff.id, userId));
        const [dept] = currentUser?.department
          ? await db.select({ id: departments.id }).from(departments).where(eq(departments.name, currentUser.department))
          : [null];
        if (!dept || dept.id !== tmpl.teamId) {
          return res.status(403).json({ error: "You can only modify templates for your own team" });
        }
      }

      const { dayNumber, sortOrder, title, description, itemType, referenceId, isRequired, resources } = req.body;

      if (!['text', 'kb_article', 'training_course'].includes(itemType)) {
        return res.status(400).json({ error: "itemType must be 'text', 'kb_article', or 'training_course'" });
      }
      if (itemType === 'text' && referenceId) {
        return res.status(400).json({ error: "referenceId must be null for text items" });
      }

      const [item] = await db.insert(onboardingTemplateItems).values({
        templateId,
        dayNumber,
        sortOrder: sortOrder || 0,
        title,
        description: description || null,
        itemType,
        referenceId: referenceId || null,
        resources: Array.isArray(resources) ? resources : [],
        isRequired: isRequired !== undefined ? isRequired : true,
      }).returning();

      await db.update(onboardingTemplates).set({ updatedAt: new Date() }).where(eq(onboardingTemplates.id, templateId));
      res.status(201).json(item);
    } catch (error: any) {
      console.error("Error creating onboarding template item:", error);
      res.status(500).json({ error: "Failed to create template item" });
    }
  });

  app.put("/api/onboarding-templates/:id/items/:itemId", requireAuth(), requirePermission('hr', 'canManage'), async (req, res) => {
    try {
      const itemId = parseInt(req.params.itemId);
      const templateId = parseInt(req.params.id);
      const { dayNumber, sortOrder, title, description, itemType, referenceId, isRequired, resources } = req.body;

      const updateData: Record<string, any> = {};
      if (dayNumber !== undefined) updateData.dayNumber = dayNumber;
      if (sortOrder !== undefined) updateData.sortOrder = sortOrder;
      if (title !== undefined) updateData.title = title;
      if (description !== undefined) updateData.description = description;
      if (itemType !== undefined) {
        if (!['text', 'kb_article', 'training_course'].includes(itemType)) {
          return res.status(400).json({ error: "itemType must be 'text', 'kb_article', or 'training_course'" });
        }
        updateData.itemType = itemType;
      }
      if (referenceId !== undefined) updateData.referenceId = referenceId;
      if (resources !== undefined) updateData.resources = Array.isArray(resources) ? resources : [];
      if (isRequired !== undefined) updateData.isRequired = isRequired;

      const [updated] = await db.update(onboardingTemplateItems)
        .set(updateData)
        .where(and(eq(onboardingTemplateItems.id, itemId), eq(onboardingTemplateItems.templateId, templateId)))
        .returning();

      if (!updated) {
        return res.status(404).json({ error: "Item not found" });
      }

      await db.update(onboardingTemplates).set({ updatedAt: new Date() }).where(eq(onboardingTemplates.id, templateId));
      res.json(updated);
    } catch (error: any) {
      console.error("Error updating onboarding template item:", error);
      res.status(500).json({ error: "Failed to update template item" });
    }
  });

  app.delete("/api/onboarding-templates/:id/items/:itemId", requireAuth(), requirePermission('hr', 'canManage'), async (req, res) => {
    try {
      const itemId = parseInt(req.params.itemId);
      const templateId = parseInt(req.params.id);
      await db.delete(onboardingTemplateItems)
        .where(and(eq(onboardingTemplateItems.id, itemId), eq(onboardingTemplateItems.templateId, templateId)));
      await db.update(onboardingTemplates).set({ updatedAt: new Date() }).where(eq(onboardingTemplates.id, templateId));
      res.json({ success: true });
    } catch (error: any) {
      console.error("Error deleting onboarding template item:", error);
      res.status(500).json({ error: "Failed to delete template item" });
    }
  });

  app.put("/api/onboarding-templates/:id/items/reorder", requireAuth(), requirePermission('hr', 'canManage'), async (req, res) => {
    try {
      const templateId = parseInt(req.params.id);
      const { items } = req.body;
      if (!Array.isArray(items)) {
        return res.status(400).json({ error: "items must be an array" });
      }

      await db.transaction(async (tx) => {
        for (const item of items) {
          await tx.update(onboardingTemplateItems)
            .set({ dayNumber: item.dayNumber, sortOrder: item.sortOrder })
            .where(and(eq(onboardingTemplateItems.id, item.id), eq(onboardingTemplateItems.templateId, templateId)));
        }
      });

      await db.update(onboardingTemplates).set({ updatedAt: new Date() }).where(eq(onboardingTemplates.id, templateId));
      res.json({ success: true });
    } catch (error: any) {
      console.error("Error reordering onboarding template items:", error);
      res.status(500).json({ error: "Failed to reorder template items" });
    }
  });

  app.get("/api/kb-articles/search", requireAuth(), async (req, res) => {
    try {
      const q = (req.query.q as string || "").trim();
      if (!q) return res.json([]);

      const results = await db.select({
        id: knowledgeBaseArticles.id,
        title: knowledgeBaseArticles.title,
        categoryId: knowledgeBaseArticles.categoryId,
        slug: knowledgeBaseArticles.slug,
      })
        .from(knowledgeBaseArticles)
        .where(and(
          eq(knowledgeBaseArticles.status, "published"),
          ilike(knowledgeBaseArticles.title, `%${q}%`)
        ))
        .limit(10);

      const withCategory = await Promise.all(results.map(async (article) => {
        let categoryName = null;
        if (article.categoryId) {
          const [cat] = await db.select({ name: knowledgeBaseCategories.name }).from(knowledgeBaseCategories).where(eq(knowledgeBaseCategories.id, article.categoryId));
          categoryName = cat?.name || null;
        }
        return { ...article, category: categoryName };
      }));

      res.json(withCategory);
    } catch (error: any) {
      console.error("Error searching KB articles:", error);
      res.status(500).json({ error: "Failed to search KB articles" });
    }
  });

